use anyhow::Result;
use serde::{Deserialize, Serialize};
use std::env;
use std::path::PathBuf;
use std::process::Command;

/// Metadata returned by `idd-<name> --metadata`.
/// All fields optional for forward/backward compatibility.
#[derive(Debug, Default, Serialize, Deserialize, PartialEq)]
struct PluginMetadata {
    /// Short description shown in `idd --help`
    pub description: Option<String>,
    /// Plugin version
    pub version: Option<String>,
    /// Minimum idd version required (semver)
    pub min_idd_version: Option<String>,
    /// MCP tools this plugin exposes (future)
    pub mcp_tools: Option<Vec<String>>,
}

const IDD_VERSION: &str = env!("CARGO_PKG_VERSION");

fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();

    if args.len() < 2 {
        print_help();
        return Ok(());
    }

    let subcommand = &args[1];

    if subcommand == "--help" || subcommand == "-h" {
        print_help();
        return Ok(());
    }
    if subcommand == "--version" || subcommand == "-V" {
        println!("idd {IDD_VERSION}");
        return Ok(());
    }

    let plugin = find_plugin(subcommand)?;

    // Check compatibility before executing
    if let Some(meta) = get_plugin_metadata(&plugin) {
        if let Some(min) = &meta.min_idd_version {
            if !version_satisfies(IDD_VERSION, min) {
                eprintln!(
                    "error: {subcommand} requires idd >= {min}, but you have idd {IDD_VERSION}"
                );
                std::process::exit(1);
            }
        }
    }

    let status = Command::new(&plugin)
        .args(&args[2..])
        .status()
        .map_err(|e| anyhow::anyhow!("failed to run {}: {e}", plugin.display()))?;

    if !status.success() {
        std::process::exit(status.code().unwrap_or(1));
    }

    Ok(())
}

fn find_plugin(subcommand: &str) -> Result<PathBuf> {
    let plugin_name = format!("idd-{subcommand}");

    let paths = env::var_os("PATH").unwrap_or_default();
    for dir in env::split_paths(&paths) {
        let candidate = dir.join(&plugin_name);
        if candidate.is_file() && is_executable(&candidate) {
            return Ok(candidate);
        }
    }

    anyhow::bail!("unknown command '{subcommand}'. Run `idd --help` for available commands.")
}

#[cfg(unix)]
fn is_executable(path: &std::path::Path) -> bool {
    use std::os::unix::fs::PermissionsExt;
    path.metadata()
        .map(|m| m.permissions().mode() & 0o111 != 0)
        .unwrap_or(false)
}

#[cfg(not(unix))]
fn is_executable(path: &std::path::Path) -> bool {
    path.is_file()
}

fn print_help() {
    println!("idd — Intent-Driven Development CLI");
    println!();
    println!("Usage: idd <command> [ARGS]...");
    println!();
    println!("Commands:");

    let plugins = discover_plugins();
    if plugins.is_empty() {
        println!("  (no plugins found on $PATH)");
    } else {
        for (name, desc) in plugins {
            println!("  {name:12} {desc}");
        }
    }

    println!();
    println!("Run `idd <command> --help` for more information on a command.");
}

fn discover_plugins() -> Vec<(String, String)> {
    let mut plugins = Vec::new();

    let paths = env::var_os("PATH").unwrap_or_default();
    for dir in env::split_paths(&paths) {
        let entries = match std::fs::read_dir(&dir) {
            Ok(e) => e,
            Err(_) => continue,
        };
        for entry in entries.flatten() {
            let name = entry.file_name();
            let name_str = name.to_string_lossy();
            if let Some(cmd) = name_str.strip_prefix("idd-") {
                if is_executable(&entry.path()) {
                    let desc = get_plugin_description(&entry.path());
                    plugins.push((cmd.to_string(), desc));
                }
            }
        }
    }

    plugins.sort_by(|a, b| a.0.cmp(&b.0));
    plugins.dedup_by(|a, b| a.0 == b.0);
    plugins
}

fn get_plugin_metadata(path: &std::path::Path) -> Option<PluginMetadata> {
    let output = Command::new(path).arg("--metadata").output().ok()?;
    if !output.status.success() {
        return None;
    }
    let stdout = String::from_utf8_lossy(&output.stdout);
    serde_json::from_str(stdout.trim()).ok()
}

fn get_plugin_description(path: &std::path::Path) -> String {
    // Try --metadata first (structured JSON)
    if let Some(meta) = get_plugin_metadata(path) {
        if let Some(desc) = meta.description {
            if !desc.is_empty() {
                return desc;
            }
        }
    }

    // Fall back to --describe (single line)
    if let Ok(output) = Command::new(path).arg("--describe").output() {
        let stdout = String::from_utf8_lossy(&output.stdout);
        let trimmed = stdout.trim().to_string();
        if !trimmed.is_empty() {
            return trimmed;
        }
    }

    // Fall back to parsing --help
    let output = match Command::new(path).arg("--help").output() {
        Ok(o) => o,
        Err(_) => return String::new(),
    };

    let stdout = String::from_utf8_lossy(&output.stdout);
    for line in stdout.lines() {
        let trimmed = line.trim();
        if !trimmed.is_empty() && !trimmed.starts_with("Usage:") && !trimmed.starts_with("idd-") {
            return trimmed.to_string();
        }
    }

    String::new()
}

/// Minimal semver check: does `actual` satisfy `>= required`?
/// Only handles MAJOR.MINOR.PATCH — good enough for our use case.
fn version_satisfies(actual: &str, required: &str) -> bool {
    let parse = |v: &str| -> Option<(u64, u64, u64)> {
        let parts: Vec<u64> = v.split('.').filter_map(|s| s.parse().ok()).collect();
        if parts.len() == 3 {
            Some((parts[0], parts[1], parts[2]))
        } else {
            None
        }
    };

    match (parse(actual), parse(required)) {
        (Some(a), Some(r)) => a >= r,
        _ => true, // If we can't parse, assume compatible
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_version_satisfies() {
        // Exact match
        assert!(version_satisfies("1.0.0", "1.0.0"));
        assert!(!version_satisfies("0.9.9", "1.0.0"));

        // Greater than
        assert!(version_satisfies("2.0.0", "1.0.0"));
        assert!(version_satisfies("1.5.0", "1.0.0"));

        // Less than
        assert!(!version_satisfies("0.9.9", "1.0.0"));
        assert!(!version_satisfies("1.0.0", "1.1.0"));

        // Patch level
        assert!(version_satisfies("1.0.5", "1.0.0"));
        assert!(!version_satisfies("1.0.0", "1.0.5"));

        // Invalid versions (should return true)
        assert!(version_satisfies("invalid", "1.0.0"));
        assert!(version_satisfies("1.0", "1.0.0"));
    }

    #[test]
    fn test_plugin_metadata_serialization() {
        let meta = PluginMetadata {
            description: Some("Test plugin".to_string()),
            version: Some("1.0.0".to_string()),
            min_idd_version: Some("0.1.0".to_string()),
            mcp_tools: Some(vec!["tool1".to_string()]),
        };

        let json = serde_json::to_string(&meta).unwrap();
        let deserialized: PluginMetadata = serde_json::from_str(&json).unwrap();

        assert_eq!(meta, deserialized);
    }

    #[test]
    fn test_plugin_metadata_partial() {
        let meta = PluginMetadata {
            description: Some("Test plugin".to_string()),
            version: None,
            min_idd_version: None,
            mcp_tools: None,
        };

        let json = serde_json::to_string(&meta).unwrap();
        let deserialized: PluginMetadata = serde_json::from_str(&json).unwrap();

        assert_eq!(meta, deserialized);
    }

    #[test]
    fn test_plugin_metadata_empty() {
        let meta = PluginMetadata::default();
        let json = serde_json::to_string(&meta).unwrap();
        let deserialized: PluginMetadata = serde_json::from_str(&json).unwrap();

        assert_eq!(meta, deserialized);
    }

    #[test]
    fn test_plugin_metadata_deserialization() {
        let json = r#"{
            "description": "Test plugin",
            "version": "1.0.0",
            "min_idd_version": "0.1.0"
        }"#;
        let meta: PluginMetadata = serde_json::from_str(json).unwrap();

        assert_eq!(meta.description, Some("Test plugin".to_string()));
        assert_eq!(meta.version, Some("1.0.0".to_string()));
        assert_eq!(meta.min_idd_version, Some("0.1.0".to_string()));
    }

    #[test]
    fn test_plugin_metadata_missing_optional_fields() {
        let json = r#""just a string""#;
        let meta: Result<PluginMetadata, _> = serde_json::from_str(json);
        assert!(meta.is_err());
    }

    #[test]
    fn test_print_help_does_not_panic() {
        print_help();
    }

    #[test]
    fn test_version_satisfies_boundary_cases() {
        assert!(version_satisfies("1.0.0", "0.0.0"));
        assert!(version_satisfies("10.0.0", "9.9.9"));
        assert!(version_satisfies("100.100.100", "1.0.0"));
        assert!(version_satisfies("1.2.3", "1.2.0"));
        assert!(version_satisfies("1.0.0", "0.9.9"));
        assert!(version_satisfies("2.0.0", "1.9.9"));
        assert!(version_satisfies("1.0.0", "1.0.0"));
        assert!(!version_satisfies("1.0.0", "1.0.1"));
        assert!(version_satisfies("1.0.1", "1.0.0"));
    }

    #[test]
    fn test_version_satisfies_invalid_versions() {
        assert!(version_satisfies("invalid", "1.0.0"));
        assert!(version_satisfies("1.0", "1.0.0"));
        assert!(version_satisfies("invalid", "1.0"));
        assert!(version_satisfies("1.0.0", "invalid"));
        assert!(version_satisfies("", "1.0.0"));
        assert!(version_satisfies("1.0.0", ""));
    }

    #[test]
    fn test_find_plugin_not_found() {
        let result = find_plugin("nonexistent_command_12345");
        assert!(result.is_err());
        assert!(result.unwrap_err().to_string().contains("unknown command"));
    }

    #[test]
    fn test_find_plugin_not_found_variations() {
        for cmd in &["foo", "bar", "baz_qux", "test123"] {
            let result = find_plugin(cmd);
            assert!(result.is_err());
        }
    }

    #[test]
    fn test_is_executable_unix() {
        #[cfg(unix)]
        {
            let temp_file = std::env::temp_dir().join("test_executable_");
            let temp_path = std::path::Path::new(&temp_file);
            std::fs::write(&temp_file, "test").unwrap();
            assert!(!is_executable(temp_path));
            use std::os::unix::fs::PermissionsExt;
            let mut perms = std::fs::metadata(temp_path).unwrap().permissions();
            perms.set_mode(0o755);
            std::fs::set_permissions(temp_path, perms).unwrap();
            assert!(is_executable(temp_path));
            std::fs::remove_file(temp_path).unwrap();
        }

        #[cfg(not(unix))]
        {
            let temp_file = std::env::temp_dir().join("test_executable_");
            std::fs::write(&temp_file, "test").unwrap();
            assert!(is_executable(std::path::Path::new(&temp_file)));
            std::fs::remove_file(temp_file).unwrap();
        }
    }

    #[test]
    fn test_is_executable_windows() {
        #[cfg(not(unix))]
        {
            let temp_file = std::env::temp_dir().join("test_executable_");
            std::fs::write(&temp_file, "test").unwrap();
            assert!(is_executable(std::path::Path::new(&temp_file)));
            std::fs::remove_file(temp_file).unwrap();
        }

        #[cfg(unix)]
        {}
    }

    #[test]
    fn test_discover_plugins_empty_path() {
        let original_path = std::env::var("PATH").ok();
        std::env::set_var("PATH", "");
        let plugins = discover_plugins();
        assert!(!plugins.contains(&("idd-".to_string(), String::new())));
        if let Some(path) = original_path {
            std::env::set_var("PATH", path);
        }
    }

    #[test]
    fn test_is_executable_permission_check() {
        #[cfg(unix)]
        {
            let temp_file = std::env::temp_dir().join("test_executable_perms");
            let temp_path = std::path::Path::new(&temp_file);

            std::fs::write(&temp_file, "test").unwrap();
            assert!(!is_executable(temp_path));

            use std::os::unix::fs::PermissionsExt;
            let mut perms = std::fs::metadata(temp_path).unwrap().permissions();
            perms.set_mode(0o755);
            std::fs::set_permissions(temp_path, perms).unwrap();

            assert!(is_executable(temp_path));

            std::fs::remove_file(temp_path).unwrap();
        }

        #[cfg(not(unix))]
        {
            let temp_file = std::env::temp_dir().join("test_executable_perms");
            std::fs::write(&temp_file, "test").unwrap();
            assert!(is_executable(std::path::Path::new(&temp_file)));
            std::fs::remove_file(temp_file).unwrap();
        }
    }

    #[test]
    fn test_get_plugin_description_fallback_chain() {
        let temp_dir = std::env::temp_dir();
        let test_plugin = temp_dir.join("idd-desc_fallback");
        std::fs::write(&test_plugin, "#!/bin/bash\necho 'custom description'").unwrap();
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let mut perms = std::fs::metadata(&test_plugin).unwrap().permissions();
            perms.set_mode(0o755);
            std::fs::set_permissions(&test_plugin, perms).unwrap();
        }
        let original_path = std::env::var("PATH").ok();
        std::env::set_var(
            "PATH",
            format!(
                "{}/{}",
                temp_dir.display(),
                std::env::var("PATH").unwrap_or_default()
            ),
        );
        let desc = get_plugin_description(std::path::Path::new(&test_plugin));
        if let Some(path) = original_path {
            std::env::set_var("PATH", path);
        }
        std::fs::remove_file(test_plugin).unwrap();
        assert!(!desc.is_empty());
    }

    #[test]
    fn test_main_help_flag() {
        let args = ["test".to_string(), "--help".to_string()];
        let subcommand = &args[1];
        assert!(subcommand == "--help" || subcommand == "-h");
    }

    #[test]
    fn test_main_version_flag() {
        let args = ["test".to_string(), "--version".to_string()];
        let subcommand = &args[1];
        assert!(subcommand == "--version" || subcommand == "-V");
    }

    #[test]
    fn test_main_no_args_shows_help() {
        let args: Vec<String> = vec![];
        assert!(args.len() < 2);
    }
}

use thiserror::Error;

#[derive(Debug, Error)]
pub enum IddError {
    #[error("subcommand failed: {0}")]
    Subcommand(String),
}

pub type Result<T> = std::result::Result<T, IddError>;

#[doc(hidden)]
pub mod __private18 {
    #[doc(hidden)]
    pub use crate::private::*;
}

use serde::{Deserialize, Serialize};

use crate::enforcement::EnforcementProfile;
use crate::scope::Scope;
use crate::severity::Severity;

#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct DeclarationId(pub String);

impl DeclarationId {
    pub fn new(id: impl Into<String>) -> Self {
        Self(id.into())
    }
}

impl std::fmt::Display for DeclarationId {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.0)
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum DeclarationKind {
    Invariant,
    Precondition,
    Postcondition,
    Assumption,
    CouplingLimit,
    Temporal,
    ResourceBound,
    ProcessConstraint,
    FeatureConstraint,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct Declaration {
    pub id: DeclarationId,
    pub kind: DeclarationKind,
    pub scope: Scope,
    pub severity: Severity,
    pub statement: String,
    pub rationale: String,
    pub owner: Option<String>,
    pub enforcement_profile: EnforcementProfile,
    pub tags: Vec<String>,
    pub overrides: Option<OverrideInfo>,
    pub feature_ref: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct OverrideInfo {
    pub overridden_id: String,
    pub rationale: String,
}

#[derive(Default)]
pub struct DeclarationBuilder {
    id: Option<String>,
    kind: Option<DeclarationKind>,
    scope: Option<Scope>,
    severity: Option<Severity>,
    statement: Option<String>,
    rationale: Option<String>,
    owner: Option<String>,
    enforcement_profile: Option<EnforcementProfile>,
    tags: Vec<String>,
    overrides: Option<OverrideInfo>,
    feature_ref: Option<String>,
}

impl DeclarationBuilder {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn id(mut self, id: impl Into<String>) -> Self {
        self.id = Some(id.into());
        self
    }

    pub fn kind(mut self, kind: DeclarationKind) -> Self {
        self.kind = Some(kind);
        self
    }

    pub fn scope(mut self, scope: Scope) -> Self {
        self.scope = Some(scope);
        self
    }

    pub fn severity(mut self, severity: Severity) -> Self {
        self.severity = Some(severity);
        self
    }

    pub fn statement(mut self, statement: impl Into<String>) -> Self {
        self.statement = Some(statement.into());
        self
    }

    pub fn rationale(mut self, rationale: impl Into<String>) -> Self {
        self.rationale = Some(rationale.into());
        self
    }

    pub fn owner(mut self, owner: impl Into<String>) -> Self {
        self.owner = Some(owner.into());
        self
    }

    pub fn enforcement_profile(mut self, profile: EnforcementProfile) -> Self {
        self.enforcement_profile = Some(profile);
        self
    }

    pub fn tag(mut self, tag: impl Into<String>) -> Self {
        self.tags.push(tag.into());
        self
    }

    pub fn overrides(
        mut self,
        overridden_id: impl Into<String>,
        rationale: impl Into<String>,
    ) -> Self {
        self.overrides = Some(OverrideInfo {
            overridden_id: overridden_id.into(),
            rationale: rationale.into(),
        });
        self
    }

    pub fn feature_ref(mut self, feature_ref: impl Into<String>) -> Self {
        self.feature_ref = Some(feature_ref.into());
        self
    }

    pub fn build(self) -> Result<Declaration, DeclarationBuildError> {
        let id = self.id.ok_or(DeclarationBuildError::MissingField("id"))?;
        let kind = self
            .kind
            .ok_or(DeclarationBuildError::MissingField("kind"))?;
        let scope = self
            .scope
            .ok_or(DeclarationBuildError::MissingField("scope"))?;
        let severity = self
            .severity
            .ok_or(DeclarationBuildError::MissingField("severity"))?;
        let statement = self
            .statement
            .ok_or(DeclarationBuildError::MissingField("statement"))?;
        let rationale = self
            .rationale
            .ok_or(DeclarationBuildError::MissingField("rationale"))?;

        Ok(Declaration {
            id: DeclarationId::new(id),
            kind,
            scope,
            severity,
            statement,
            rationale,
            owner: self.owner,
            enforcement_profile: self
                .enforcement_profile
                .unwrap_or_else(|| EnforcementProfile::new(Vec::new())),
            tags: self.tags,
            overrides: self.overrides,
            feature_ref: self.feature_ref,
        })
    }
}

#[derive(Debug, thiserror::Error)]
pub enum DeclarationBuildError {
    #[error("missing required field: {0}")]
    MissingField(&'static str),
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::{EnforcementPoint, EnforcementProfile};
    use proptest::prelude::*;

    fn arb_declaration() -> impl Strategy<Value = Declaration> {
        (
            any::<String>(),
            prop_oneof![
                Just(DeclarationKind::Invariant),
                Just(DeclarationKind::Precondition),
                Just(DeclarationKind::Postcondition),
                Just(DeclarationKind::Assumption),
                Just(DeclarationKind::CouplingLimit),
                Just(DeclarationKind::Temporal),
                Just(DeclarationKind::ResourceBound),
                Just(DeclarationKind::ProcessConstraint),
                Just(DeclarationKind::FeatureConstraint),
            ],
            prop_oneof![
                Just(Scope::Global),
                Just(Scope::Platform),
                Just(Scope::Project),
                Just(Scope::Domain),
                Just(Scope::Module),
                Just(Scope::Interface),
                Just(Scope::Function),
            ],
            prop_oneof![
                Just(Severity::Hard),
                Just(Severity::Soft),
                Just(Severity::Info),
            ],
            any::<String>(),
            any::<String>(),
            proptest::option::of(any::<String>()),
            proptest::collection::vec(
                prop_oneof![
                    Just(EnforcementPoint::Expression),
                    Just(EnforcementPoint::Development),
                    Just(EnforcementPoint::PropertyBasedTests),
                    Just(EnforcementPoint::ReasoningTools),
                    Just(EnforcementPoint::PreCommit),
                    Just(EnforcementPoint::Ci),
                    Just(EnforcementPoint::Runtime),
                ],
                0..=7,
            ),
            proptest::collection::vec(any::<String>(), 0..=5),
            proptest::option::of(any::<String>()),
        )
            .prop_map(
                |(
                    id,
                    kind,
                    scope,
                    severity,
                    statement,
                    rationale,
                    owner,
                    points,
                    tags,
                    feature_ref,
                )| {
                    Declaration {
                        id: DeclarationId::new(id),
                        kind,
                        scope,
                        severity,
                        statement,
                        rationale,
                        owner,
                        enforcement_profile: EnforcementProfile::new(points),
                        tags,
                        overrides: None,
                        feature_ref,
                    }
                },
            )
    }

    proptest! {
        #[test]
        fn declaration_json_roundtrip(decl in arb_declaration()) {
            let json = serde_json::to_string(&decl).unwrap();
            let parsed: Declaration = serde_json::from_str(&json).unwrap();
            prop_assert_eq!(decl, parsed);
        }

        #[test]
        fn declaration_serde_preserves_all_fields(decl in arb_declaration()) {
            let json = serde_json::to_value(&decl).unwrap();
            prop_assert!(json.get("id").is_some());
            prop_assert!(json.get("kind").is_some());
            prop_assert!(json.get("scope").is_some());
            prop_assert!(json.get("severity").is_some());
            prop_assert!(json.get("statement").is_some());
            prop_assert!(json.get("rationale").is_some());
            if decl.owner.is_some() {
                prop_assert!(json.get("owner").is_some());
            }
            if decl.feature_ref.is_some() {
                prop_assert!(json.get("feature_ref").is_some());
            }
        }
    }

    // ── Invalid input rejection ─────────────────────────────

    proptest! {
        #[test]
        fn invalid_json_deserialization_fails(
            garbage in any::<String>(),
        ) {
            let result: Result<Declaration, _> = serde_json::from_str(&garbage);
            if result.is_ok() {
                let decl = result.unwrap();
                prop_assert!(!decl.id.0.is_empty());
                prop_assert!(!decl.statement.is_empty());
                prop_assert!(!decl.rationale.is_empty());
            }
        }

        #[test]
        fn builder_rejects_missing_required_fields(
            mask in 1u8..63u8,
        ) {
            let missing_id = mask & (1 << 0) != 0;
            let missing_kind = mask & (1 << 1) != 0;
            let missing_scope = mask & (1 << 2) != 0;
            let missing_severity = mask & (1 << 3) != 0;
            let missing_statement = mask & (1 << 4) != 0;
            let missing_rationale = mask & (1 << 5) != 0;

            let mut b = DeclarationBuilder::new();
            if !missing_id { b = b.id("test"); }
            if !missing_kind { b = b.kind(DeclarationKind::Invariant); }
            if !missing_scope { b = b.scope(Scope::Project); }
            if !missing_severity { b = b.severity(Severity::Hard); }
            if !missing_statement { b = b.statement("test"); }
            if !missing_rationale { b = b.rationale("test"); }

            let result = b.build();
            prop_assert!(result.is_err());
        }

        #[test]
        fn unknown_enum_variant_json_fails(
            kind in "[a-zA-Z0-9_-]+",
        ) {
            let json = format!(
                r#"{{"id":"x","kind":"{}","scope":"project","severity":"hard","statement":"s","rationale":"r"}}"#,
                kind
            );
            let result: Result<Declaration, _> = serde_json::from_str(&json);
            prop_assert!(result.is_err() || kind == "invariant" || kind == "precondition"
                || kind == "postcondition" || kind == "assumption" || kind == "coupling_limit"
                || kind == "temporal" || kind == "resource_bound" || kind == "process_constraint"
                || kind == "feature_constraint");
        }

        #[test]
        fn unknown_scope_json_fails(
            scope in "[a-zA-Z0-9_-]+",
        ) {
            let json = format!(
                r#"{{"id":"x","kind":"invariant","scope":"{}","severity":"hard","statement":"s","rationale":"r"}}"#,
                scope
            );
            let result: Result<Declaration, _> = serde_json::from_str(&json);
            prop_assert!(result.is_err() || scope == "global" || scope == "platform"
                || scope == "project" || scope == "domain" || scope == "module"
                || scope == "interface" || scope == "function");
        }

        #[test]
        fn unknown_severity_json_fails(
            severity in "[a-zA-Z0-9_-]+",
        ) {
            let json = format!(
                r#"{{"id":"x","kind":"invariant","scope":"project","severity":"{}","statement":"s","rationale":"r"}}"#,
                severity
            );
            let result: Result<Declaration, _> = serde_json::from_str(&json);
            prop_assert!(result.is_err() || severity == "hard" || severity == "soft" || severity == "info");
        }

        #[test]
        fn malformed_json_never_panics(
            bytes in proptest::collection::vec(0u8..=255, 0..=512),
        ) {
            let s = String::from_utf8_lossy(&bytes);
            let _: Result<Declaration, _> = serde_json::from_str(&s);
        }

        #[test]
        fn structurally_valid_but_wrong_type_fails(
            value in prop_oneof![
                Just(serde_json::Value::Null),
                Just(serde_json::Value::Bool(true)),
                Just(serde_json::Value::Bool(false)),
                Just(serde_json::Value::Number(0.into())),
                Just(serde_json::Value::Array(vec![])),
            ],
        ) {
            let json = serde_json::to_string(&value).unwrap();
            let result: Result<Declaration, _> = serde_json::from_str(&json);
            prop_assert!(result.is_err());
        }

        #[test]
        fn deeply_nested_json_fails(
            depth in 10usize..=100usize,
        ) {
            let mut json = String::from(r#"{"id":"x","kind":"invariant","scope":"project","severity":"hard","statement":"s","rationale":"r","enforcement_profile":{},"tags":[],"overrides":{},"feature_ref":null,""#);
            for _ in 0..depth {
                json.push_str(r#""nested":{"#);
            }
            json.push_str(r#""x":1"#);
            for _ in 0..depth {
                json.push('}');
            }
            json.push('}');

            let result: Result<Declaration, _> = serde_json::from_str(&json);
            prop_assert!(result.is_err());
        }
    }
}

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum EnforcementPoint {
    Expression,
    Development,
    PropertyBasedTests,
    ReasoningTools,
    PreCommit,
    Ci,
    Runtime,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct EnforcementProfile {
    pub points: Vec<EnforcementPoint>,
}

impl EnforcementProfile {
    pub fn new(points: Vec<EnforcementPoint>) -> Self {
        Self { points }
    }

    pub fn is_point_active(&self, point: &EnforcementPoint) -> bool {
        self.points.contains(point)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_enforcement_profile_creation() {
        let profile = EnforcementProfile::new(vec![
            EnforcementPoint::Expression,
            EnforcementPoint::PreCommit,
        ]);

        assert_eq!(profile.points.len(), 2);
        assert!(profile.is_point_active(&EnforcementPoint::Expression));
        assert!(profile.is_point_active(&EnforcementPoint::PreCommit));
        assert!(!profile.is_point_active(&EnforcementPoint::Runtime));
    }

    #[test]
    fn test_is_point_active_all_variants() {
        let profile = EnforcementProfile::new(vec![
            EnforcementPoint::Expression,
            EnforcementPoint::Development,
            EnforcementPoint::PropertyBasedTests,
            EnforcementPoint::ReasoningTools,
            EnforcementPoint::PreCommit,
            EnforcementPoint::Ci,
            EnforcementPoint::Runtime,
        ]);

        // All points should be active
        assert!(profile.is_point_active(&EnforcementPoint::Expression));
        assert!(profile.is_point_active(&EnforcementPoint::Development));
        assert!(profile.is_point_active(&EnforcementPoint::PropertyBasedTests));
        assert!(profile.is_point_active(&EnforcementPoint::ReasoningTools));
        assert!(profile.is_point_active(&EnforcementPoint::PreCommit));
        assert!(profile.is_point_active(&EnforcementPoint::Ci));
        assert!(profile.is_point_active(&EnforcementPoint::Runtime));
    }

    #[test]
    fn test_empty_profile() {
        let profile = EnforcementProfile::new(vec![]);

        assert!(!profile.is_point_active(&EnforcementPoint::Expression));
        assert!(!profile.is_point_active(&EnforcementPoint::Runtime));
    }

    #[test]
    fn test_serialization_roundtrip() {
        let profile = EnforcementProfile::new(vec![
            EnforcementPoint::Expression,
            EnforcementPoint::PreCommit,
            EnforcementPoint::Ci,
        ]);

        let json = serde_json::to_string(&profile).unwrap();
        let deserialized: EnforcementProfile = serde_json::from_str(&json).unwrap();

        assert_eq!(profile.points.len(), deserialized.points.len());
        for (p1, p2) in profile.points.iter().zip(deserialized.points.iter()) {
            assert_eq!(p1, p2);
        }
    }

    #[test]
    fn test_deserialization_all_variants() {
        let json = r#"{"points": ["expression", "development", "property_based_tests", "reasoning_tools", "pre_commit", "ci", "runtime"]}"#;
        let profile: EnforcementProfile = serde_json::from_str(json).unwrap();

        assert_eq!(profile.points.len(), 7);
        assert!(profile.is_point_active(&EnforcementPoint::Expression));
        assert!(profile.is_point_active(&EnforcementPoint::Development));
        assert!(profile.is_point_active(&EnforcementPoint::PropertyBasedTests));
        assert!(profile.is_point_active(&EnforcementPoint::ReasoningTools));
        assert!(profile.is_point_active(&EnforcementPoint::PreCommit));
        assert!(profile.is_point_active(&EnforcementPoint::Ci));
        assert!(profile.is_point_active(&EnforcementPoint::Runtime));
    }

    #[test]
    fn test_deserialization_unknown_variant() {
        let json = r#"{"points": ["expression", "unknown_variant"]}"#;
        let result: Result<EnforcementProfile, _> = serde_json::from_str(json);
        assert!(result.is_err());
    }

    #[test]
    fn test_enforcement_point_serialization() {
        let point = EnforcementPoint::Expression;
        let json = serde_json::to_string(&point).unwrap();
        assert_eq!(json, r#""expression""#);

        let point = EnforcementPoint::Runtime;
        let json = serde_json::to_string(&point).unwrap();
        assert_eq!(json, r#""runtime""#);
    }

    #[test]
    fn enforcement_profile_contains_all_points() {
        let points = vec![
            EnforcementPoint::Expression,
            EnforcementPoint::Development,
            EnforcementPoint::PropertyBasedTests,
            EnforcementPoint::ReasoningTools,
            EnforcementPoint::PreCommit,
            EnforcementPoint::Ci,
            EnforcementPoint::Runtime,
        ];
        let profile = EnforcementProfile::new(points.clone());
        for point in &points {
            assert!(profile.is_point_active(point));
        }
    }

    #[test]
    fn enforcement_point_json_roundtrip() {
        let points = vec![
            EnforcementPoint::Expression,
            EnforcementPoint::Development,
            EnforcementPoint::PropertyBasedTests,
            EnforcementPoint::ReasoningTools,
            EnforcementPoint::PreCommit,
            EnforcementPoint::Ci,
            EnforcementPoint::Runtime,
        ];
        for point in &points {
            let json = serde_json::to_string(point).unwrap();
            let deserialized: EnforcementPoint = serde_json::from_str(&json).unwrap();
            assert_eq!(point, &deserialized);
        }
    }

    #[test]
    fn empty_profile_has_no_active_points() {
        let profile = EnforcementProfile::new(vec![]);
        for point in &[
            &EnforcementPoint::Expression,
            &EnforcementPoint::Development,
            &EnforcementPoint::PropertyBasedTests,
            &EnforcementPoint::ReasoningTools,
            &EnforcementPoint::PreCommit,
            &EnforcementPoint::Ci,
            &EnforcementPoint::Runtime,
        ] {
            assert!(!profile.is_point_active(point));
        }
    }

    #[test]
    fn serialization_does_not_contain_unknown_variants() {
        let points = vec![
            EnforcementPoint::Expression,
            EnforcementPoint::PreCommit,
            EnforcementPoint::Runtime,
        ];
        let profile = EnforcementProfile::new(points);
        let json = serde_json::to_string(&profile).unwrap();
        // Verify JSON only contains known variant names
        assert!(!json.contains("unknown"));
        assert!(!json.contains("INVALID"));
    }
}

