/// Parser for IDD `.intent` files.
///
/// Reads TOML-formatted intent files and produces `idd-dsl-core` data model instances.
pub mod parser;

pub use parser::parse_intent_file;

use std::path::Path;

use idd_dsl_core::{
    Declaration, DeclarationId, DeclarationKind, EnforcementPoint, EnforcementProfile,
    ImportBinding, ImportDeclaration, Scope, Severity,
};
use serde::Deserialize;
use thiserror::Error;

#[derive(Debug, Error)]
pub enum ParseError {
    #[error("failed to read file: {0}")]
    Io(#[from] std::io::Error),

    #[error("failed to parse TOML: {0}")]
    Toml(#[from] toml::de::Error),

    #[error("invalid declaration kind: {0}")]
    InvalidKind(String),

    #[error("invalid scope: {0}")]
    InvalidScope(String),

    #[error("invalid severity: {0}")]
    InvalidSeverity(String),

    #[error("invalid enforcement point: {0}")]
    InvalidEnforcementPoint(String),

    #[error("duplicate declaration ID '{0}' in {1}")]
    DuplicateId(String, String),
}

#[derive(Debug, Deserialize)]
struct TomlIntentFile {
    #[serde(default)]
    declaration: Vec<TomlDeclaration>,
    #[serde(default)]
    import: Vec<TomlImport>,
}

#[derive(Debug, Deserialize)]
struct TomlDeclaration {
    id: String,
    kind: String,
    scope: String,
    severity: String,
    statement: String,
    rationale: String,
    #[serde(default)]
    owner: Option<String>,
    #[serde(default)]
    enforcement_points: Vec<String>,
    #[serde(default)]
    tags: Vec<String>,
    #[serde(default)]
    r#override: Option<TomlOverride>,
    #[serde(default)]
    feature_ref: Option<String>,
}

#[derive(Debug, Deserialize)]
struct TomlOverride {
    overridden_id: String,
    rationale: String,
}

#[derive(Debug, Deserialize)]
struct TomlImport {
    library: String,
    version: String,
    #[serde(default)]
    bindings: Vec<TomlBinding>,
}

#[derive(Debug, Deserialize)]
struct TomlBinding {
    abstract_role: String,
    concrete_module: String,
}

#[derive(Debug)]
pub struct IntentFile {
    pub declarations: Vec<Declaration>,
    pub imports: Vec<ImportDeclaration>,
}

fn parse_kind(s: &str) -> Result<DeclarationKind, ParseError> {
    match s {
        "invariant" => Ok(DeclarationKind::Invariant),
        "precondition" => Ok(DeclarationKind::Precondition),
        "postcondition" => Ok(DeclarationKind::Postcondition),
        "assumption" => Ok(DeclarationKind::Assumption),
        "coupling_limit" => Ok(DeclarationKind::CouplingLimit),
        "temporal" => Ok(DeclarationKind::Temporal),
        "resource_bound" => Ok(DeclarationKind::ResourceBound),
        "process_constraint" => Ok(DeclarationKind::ProcessConstraint),
        "feature_constraint" => Ok(DeclarationKind::FeatureConstraint),
        other => Err(ParseError::InvalidKind(other.into())),
    }
}

fn parse_scope(s: &str) -> Result<Scope, ParseError> {
    match s {
        "global" => Ok(Scope::Global),
        "platform" => Ok(Scope::Platform),
        "project" => Ok(Scope::Project),
        "domain" => Ok(Scope::Domain),
        "module" => Ok(Scope::Module),
        "interface" => Ok(Scope::Interface),
        "function" => Ok(Scope::Function),
        other => Err(ParseError::InvalidScope(other.into())),
    }
}

fn parse_severity(s: &str) -> Result<Severity, ParseError> {
    match s {
        "hard" => Ok(Severity::Hard),
        "soft" => Ok(Severity::Soft),
        "info" => Ok(Severity::Info),
        other => Err(ParseError::InvalidSeverity(other.into())),
    }
}

fn parse_enforcement_point(s: &str) -> Result<EnforcementPoint, ParseError> {
    match s {
        "expression" => Ok(EnforcementPoint::Expression),
        "development" => Ok(EnforcementPoint::Development),
        "property_based_tests" => Ok(EnforcementPoint::PropertyBasedTests),
        "reasoning_tools" => Ok(EnforcementPoint::ReasoningTools),
        "pre_commit" => Ok(EnforcementPoint::PreCommit),
        "ci" => Ok(EnforcementPoint::Ci),
        "runtime" => Ok(EnforcementPoint::Runtime),
        other => Err(ParseError::InvalidEnforcementPoint(other.into())),
    }
}

fn toml_to_declaration(t: TomlDeclaration) -> Result<Declaration, ParseError> {
    let kind = parse_kind(&t.kind)?;
    let scope = parse_scope(&t.scope)?;
    let severity = parse_severity(&t.severity)?;

    let points: Result<Vec<_>, _> = t
        .enforcement_points
        .iter()
        .map(|s| parse_enforcement_point(s))
        .collect();
    let enforcement_profile = EnforcementProfile::new(points?);

    let overrides = t
        .r#override
        .map(|o| idd_dsl_core::declaration::OverrideInfo {
            overridden_id: o.overridden_id,
            rationale: o.rationale,
        });

    Ok(Declaration {
        id: DeclarationId::new(t.id),
        kind,
        scope,
        severity,
        statement: t.statement,
        rationale: t.rationale,
        owner: t.owner,
        enforcement_profile,
        tags: t.tags,
        overrides,
        feature_ref: t.feature_ref,
    })
}

fn toml_to_import(t: TomlImport) -> ImportDeclaration {
    ImportDeclaration {
        library: t.library,
        version: t.version,
        bindings: t
            .bindings
            .into_iter()
            .map(|b| ImportBinding {
                abstract_role: b.abstract_role,
                concrete_module: b.concrete_module,
            })
            .collect(),
    }
}

pub fn parse_intent_file(path: &Path) -> Result<IntentFile, ParseError> {
    let content = std::fs::read_to_string(path)?;
    let doc: TomlIntentFile = toml::from_str(&content)?;

    let declarations: Result<Vec<_>, _> = doc
        .declaration
        .into_iter()
        .map(toml_to_declaration)
        .collect();

    let imports = doc.import.into_iter().map(toml_to_import).collect();

    Ok(IntentFile {
        declarations: declarations?,
        imports,
    })
}

/// Check for duplicate declaration IDs across multiple parsed intent files.
/// Returns an error for the first duplicate found.
pub fn check_duplicate_ids(
    files: &[(impl AsRef<std::path::Path>, &IntentFile)],
) -> Result<(), ParseError> {
    let mut seen = std::collections::HashMap::new();
    for (path, file) in files {
        for decl in &file.declarations {
            let id = &decl.id.0;
            let path_str = path.as_ref().display().to_string();
            if let Some(prev_path) = seen.insert(id.clone(), path_str) {
                return Err(ParseError::DuplicateId(
                    id.clone(),
                    format!("{} and {}", prev_path, path.as_ref().display()),
                ));
            }
        }
    }
    Ok(())
}

