extern crate proc_macro;

use darling::{ast::NestedMeta, FromMeta};
use idd_dsl_core::{DeclarationBuilder, DeclarationKind, EnforcementProfile, Scope, Severity};
use proc_macro::TokenStream;
use quote::quote;

#[derive(Debug, Clone, FromMeta)]
#[allow(dead_code)]
struct IntentArgs {
    id: String,
    kind: IntentKind,
    #[darling(default)]
    scope: Option<IntentScope>,
    #[darling(default)]
    severity: Option<IntentSeverity>,
    statement: String,
    rationale: String,
    #[darling(default)]
    owner: Option<String>,
    #[darling(default)]
    tags: Option<String>,
    #[darling(default)]
    overrides: Option<String>,
    #[darling(default)]
    override_rationale: Option<String>,
    #[darling(default)]
    feature_ref: Option<String>,
}

#[derive(Debug, Clone, FromMeta)]
#[allow(non_camel_case_types)]
enum IntentKind {
    invariant,
    precondition,
    postcondition,
    assumption,
    coupling_limit,
    temporal,
    resource_bound,
    process_constraint,
    feature_constraint,
}

impl From<IntentKind> for DeclarationKind {
    fn from(k: IntentKind) -> Self {
        match k {
            IntentKind::invariant => DeclarationKind::Invariant,
            IntentKind::precondition => DeclarationKind::Precondition,
            IntentKind::postcondition => DeclarationKind::Postcondition,
            IntentKind::assumption => DeclarationKind::Assumption,
            IntentKind::coupling_limit => DeclarationKind::CouplingLimit,
            IntentKind::temporal => DeclarationKind::Temporal,
            IntentKind::resource_bound => DeclarationKind::ResourceBound,
            IntentKind::process_constraint => DeclarationKind::ProcessConstraint,
            IntentKind::feature_constraint => DeclarationKind::FeatureConstraint,
        }
    }
}

#[derive(Debug, Clone, FromMeta)]
#[allow(non_camel_case_types)]
enum IntentScope {
    global,
    platform,
    project,
    domain,
    module,
    interface,
    function,
}

impl From<IntentScope> for Scope {
    fn from(s: IntentScope) -> Self {
        match s {
            IntentScope::global => Scope::Global,
            IntentScope::platform => Scope::Platform,
            IntentScope::project => Scope::Project,
            IntentScope::domain => Scope::Domain,
            IntentScope::module => Scope::Module,
            IntentScope::interface => Scope::Interface,
            IntentScope::function => Scope::Function,
        }
    }
}

#[derive(Debug, Clone, FromMeta)]
#[allow(non_camel_case_types)]
enum IntentSeverity {
    hard,
    soft,
    info,
}

impl From<IntentSeverity> for Severity {
    fn from(s: IntentSeverity) -> Self {
        match s {
            IntentSeverity::hard => Severity::Hard,
            IntentSeverity::soft => Severity::Soft,
            IntentSeverity::info => Severity::Info,
        }
    }
}

impl IntentArgs {
    fn to_declaration(&self) -> Result<idd_dsl_core::Declaration, String> {
        DeclarationBuilder::new()
            .id(&self.id)
            .kind(self.kind.clone().into())
            .scope(
                self.scope
                    .clone()
                    .map(Scope::from)
                    .unwrap_or(Scope::Function),
            )
            .severity(
                self.severity
                    .clone()
                    .map(Severity::from)
                    .unwrap_or(Severity::Hard),
            )
            .statement(&self.statement)
            .rationale(&self.rationale)
            .owner(self.owner.clone().unwrap_or_default())
            .enforcement_profile(EnforcementProfile::new(vec![]))
            .build()
            .map_err(|e| e.to_string())
    }
}

#[proc_macro_attribute]
pub fn intent(args: TokenStream, input: TokenStream) -> TokenStream {
    let attr_args = syn::parse_macro_input!(args with syn::punctuated::Punctuated::<syn::Meta, syn::Token![,]>::parse_terminated);
    let attr_args: Vec<NestedMeta> = attr_args.into_iter().map(NestedMeta::Meta).collect();

    let args = match IntentArgs::from_list(&attr_args) {
        Ok(v) => v,
        Err(e) => return e.write_errors().into(),
    };

    // Validate declaration at compile time
    if let Err(e) = args.to_declaration() {
        return syn::Error::new(proc_macro::Span::call_site().into(), e)
            .to_compile_error()
            .into();
    }

    let input_fn: syn::ItemFn = match syn::parse(input) {
        Ok(f) => f,
        Err(e) => return e.to_compile_error().into(),
    };

    let fn_vis = &input_fn.vis;
    let fn_attrs = &input_fn.attrs;
    let fn_block = &input_fn.block;
    let fn_sig = &input_fn.sig;

    // TODO: emit sidecar file — requires proc_macro_span (nightly) or external extraction tool
    // For now, validation at compile time is the enforcement point.
    // Sidecar emission will be handled by a `syn`-based source scanner in idd-cli.

    let output = quote! {
        #(#fn_attrs)*
        #fn_vis #fn_sig #fn_block
    };

    output.into()
}

