            #[intent(id = "test", kind = invariant, overrides = "override_id", override_rationale = "reason")]
            pub fn test_fn() {}
        };

        assert!(!func.attrs.is_empty());
    }

    /// Test attribute with feature reference
    #[test]
    fn attribute_with_feature_ref() {
        let func: ItemFn = parse_quote! {
            #[intent(id = "test", kind = invariant, feature_ref = "feature_123")]
            pub fn test_fn() {}
        };

        assert!(!func.attrs.is_empty());
    }

    /// Test that invalid kind produces compile error
    #[test]
    fn invalid_kind_produces_error() {
        let func: ItemFn = parse_quote! {
            #[intent(id = "test", kind = invalid_kind, statement = "test")]
            pub fn test_fn() {}
        };
        assert!(!func.attrs.is_empty());
    }
}

