fn parse_status(s: &str) -> Result<FeatureStatus> {
    match s {
        "wish" => Ok(FeatureStatus::Wish),
        "exploring" => Ok(FeatureStatus::Exploring),
        "scoping" => Ok(FeatureStatus::Scoping),
        "designing" => Ok(FeatureStatus::Designing),
        "ready" => Ok(FeatureStatus::Ready),
        "in-progress" => Ok(FeatureStatus::InProgress),
        "verifying" => Ok(FeatureStatus::Verifying),
        "done" => Ok(FeatureStatus::Done),
        "abandoned" => Ok(FeatureStatus::Abandoned),
        "deferred" => Ok(FeatureStatus::Deferred),
        _ => anyhow::bail!("invalid status: {s}"),
    }
}

#[derive(Parser)]
#[command(name = "idd-fir", about = "Feature Intent Registry CLI", version)]
struct Cli {
    #[arg(short, long, default_value = ".")]
    root: std::path::PathBuf,

    #[command(subcommand)]
    command: FirCommand,
}

#[derive(Subcommand)]
enum FirCommand {
    /// Create a new feature, story, or decision
    New(NewArgs),
    /// List features by filter criteria
    List(ListArgs),
    /// Show an entity with its relationships
    Show(ShowArgs),
    /// Advance a feature to the next natural status
    Promote(PromoteArgs),
    /// Set a feature's status explicitly
    Status(StatusArgs),
    /// Defer a feature with a recorded reason
    Defer(DeferArgs),
    /// Abandon a feature with a recorded reason
    Abandon(AbandonArgs),
    /// Create a relationship between entities
    Link(LinkArgs),
    /// Create a decision record
    Decide(DecideArgs),
    /// Show the dependency graph
    Graph(GraphArgs),
    /// Show agent context preview
    Context(ContextArgs),
    /// Run integrity and health checks
    Check(CheckArgs),
    Update(UpdateArgs),
    Search(SearchArgs),
    Note(NoteArgs),
}

