fn main() -> Result<()> {
    let args: Vec<String> = std::env::args().collect();
    if args.iter().any(|a| a == "--describe") {
        println!("Feature Intent Registry — track features, stories, and constraints");
        return Ok(());
    }
    if args.iter().any(|a| a == "--metadata") {
        println!(
            r#"{{"description":"Feature Intent Registry — track features, stories, and constraints","version":"{}"}}"#,
            env!("CARGO_PKG_VERSION")
        );
        return Ok(());
    }

    let cli = Cli::parse();

    match cli.command {
        FirCommand::New(args) => cmd_new(&cli.root, args),
        FirCommand::List(args) => cmd_list(&cli.root, args),
        FirCommand::Show(args) => cmd_show(&cli.root, args),
        FirCommand::Promote(args) => cmd_promote(&cli.root, args),
        FirCommand::Status(args) => cmd_status(&cli.root, args),
        FirCommand::Defer(args) => cmd_defer(&cli.root, args),
        FirCommand::Abandon(args) => cmd_abandon(&cli.root, args),
        FirCommand::Link(args) => cmd_link(&cli.root, args),
        FirCommand::Decide(args) => cmd_decide(&cli.root, args),
        FirCommand::Graph(args) => cmd_graph(&cli.root, args),
        FirCommand::Context(args) => cmd_context(&cli.root, args),
        FirCommand::Check(args) => cmd_check(&cli.root, args),
        FirCommand::Update(args) => {
            let mut backend = load_backend(&cli.root)?;
            cmd_update(&mut backend, args)
        }
        FirCommand::Search(args) => {
            let backend = load_backend(&cli.root)?;
            cmd_search(&backend, args)
        }
        FirCommand::Note(args) => {
            let mut backend = load_backend(&cli.root)?;
            cmd_note(&mut backend, args)
        }
    }
}

fn load_backend(root: &Path) -> Result<FileBackend> {
    FileBackend::new(root.to_path_buf())
        .map_err(|e| anyhow::anyhow!("failed to load FIR registry: {e}"))
}

fn load_registry(root: &Path) -> Result<(FileBackend, Registry)> {
    let mut backend = load_backend(root)?;
    let registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;
    Ok((backend, registry))
}

fn load_feature_mut(
    _backend: &mut impl FirBackend,
    registry: &Registry,
    id: &str,
) -> Result<(FeatureId, Feature)> {
    let fid = FeatureId(id.to_string());
    let feature = registry
        .feature(&fid)
        .cloned()
        .ok_or_else(|| anyhow::anyhow!("Feature {id} not found"))?;
    Ok((fid, feature))
}

fn dedup_push<T: PartialEq>(vec: &mut Vec<T>, items: impl IntoIterator<Item = T>) {
    for item in items {
        if !vec.contains(&item) {
            vec.push(item);
        }
    }
}

fn cmd_new(root: &Path, args: NewArgs) -> Result<()> {
    let mut backend = load_backend(root)?;
    let mut registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;

    let today = chrono::Utc::now().naive_utc().date();
    let constraints: Vec<_> = args
        .constraint
        .iter()
        .cloned()
        .map(idd_dsl_core::DeclarationId)
        .collect();
    let body = args.body.clone().unwrap_or_default();

    match args.kind {
        NewKind::Feature => {
            let id = registry.alloc_feature_id();
            let feature = new_feature(&id, &args, today, constraints, body)?;
            backend
                .save_feature(&feature)
                .map_err(|e| anyhow::anyhow!("{e}"))?;
            println!("Created feature {id}: {}", feature.title);
        }
        NewKind::Story => {
            let id = registry.alloc_story_id();
            let story = new_story(&id, &args, today, constraints, body);
            backend
                .save_story(&story)
                .map_err(|e| anyhow::anyhow!("{e}"))?;
            println!("Created story {id}: {}", story.title);
        }
        NewKind::Decision => {
            let id = registry.alloc_decision_id();
            let decision = new_decision(&id, &args, today, constraints, body);
            backend
                .save_decision(&decision)
                .map_err(|e| anyhow::anyhow!("{e}"))?;
            println!("Created decision {id}: {}", decision.title);
        }
    }

    Ok(())
}

fn new_feature(
    id: &FeatureId,
    args: &NewArgs,
    today: chrono::NaiveDate,
    constraints: Vec<idd_dsl_core::DeclarationId>,
    body: String,
) -> Result<Feature> {
    Ok(Feature {
        id: id.clone(),
        title: args.title.clone(),
        status: parse_status(&args.status)?,
        created: today,
        updated: None,
        author: std::env::var("USER")
            .ok()
            .or_else(|| std::env::var("USERNAME").ok()),
        promoted_from: None,
        promoted_date: None,
        story: args.story.as_ref().map(|s| StoryId(s.clone())),
        depends_on: args
            .depends_on
            .iter()
            .map(|s| FeatureId(s.clone()))
            .collect(),
        blocks: Vec::new(),
        related: Vec::new(),
        children: Vec::new(),
        constraints,
        preliminary_constraints: Vec::new(),
        decisions: Vec::new(),
        source: None,
        conversations: Vec::new(),
        tags: args.tag.clone(),
        priority: None,
        effort_estimate: None,
        external: None,
        body,
    })
}

fn new_story(
    id: &StoryId,
    args: &NewArgs,
    today: chrono::NaiveDate,
    constraints: Vec<idd_dsl_core::DeclarationId>,
    body: String,
) -> Story {
    Story {
        id: id.clone(),
        title: args.title.clone(),
        status: args.status.clone(),
        created: today,
        features: Vec::new(),
        constraints,
        tags: args.tag.clone(),
        body,
    }
}

fn new_decision(
    id: &DecisionId,
    args: &NewArgs,
    today: chrono::NaiveDate,
    constraints: Vec<idd_dsl_core::DeclarationId>,
    body: String,
) -> Decision {
    Decision {
        id: id.clone(),
        title: args.title.clone(),
        date: today,
        status: "proposed".into(),
        features: args
            .depends_on
            .iter()
            .map(|s| FeatureId(s.clone()))
            .collect(),
        constraints,
        body,
    }
}

fn cmd_list(root: &Path, args: ListArgs) -> Result<()> {
    let mut backend = load_backend(root)?;
    let registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;

    let mut query = Query::new(&registry);

    if !args.status.is_empty() {
        let statuses: Vec<FeatureStatus> = args
            .status
            .iter()
            .filter_map(|s| parse_status(s).ok())
            .collect();
        query = query.status(statuses);
    }

    if let Some(tag) = args.tag {
        query = query.tag(tag);
    }

    if let Some(story) = args.story {
        query = query.story(StoryId(story));
    }

    if let Some(blocks) = args.blocks {
        query = query.blocks(FeatureId(blocks));
    }

    if let Some(constraint) = args.constraint {
        query = query.constraint(constraint);
    }

    if let Some(depends_on) = args.depends_on {
        query = query.depends_on(FeatureId(depends_on));
    }

    if let Some(days) = args.stale_days {
        let now = chrono::Utc::now().naive_utc().date();
        query = query.recent_days(days, now);
    }

    let features = query.resolve();

    if features.is_empty() {
        println!("No features match the given criteria.");
        return Ok(());
    }

    for f in &features {
        let deps_suffix = join_display(&f.depends_on)
            .map(|d| format!(" — depends on: {d}"))
            .unwrap_or_default();
        println!("- {} [{}] {}{deps_suffix}", f.id.0, f.status, f.title);
    }

    Ok(())
}

fn cmd_show(root: &Path, args: ShowArgs) -> Result<()> {
    let mut backend = load_backend(root)?;
    let registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;

    if let Some(feature) = registry.features.iter().find(|f| f.id.0 == args.id) {
        println!("Feature: {} — {}", feature.id.0, feature.title);
        println!("Status: {}", feature.status);
        if let Some(author) = &feature.author {
            println!("Author: {author}");
        }
        println!("Created: {}", feature.created);
        print_if_nonempty("Tags", join_display(&feature.tags));
        print_if_nonempty("Depends on", join_display(&feature.depends_on));
        print_if_nonempty("Blocks", join_display(&feature.blocks));
        print_if_nonempty("Constraints", join_display(&feature.constraints));
        print_if_nonempty("Decisions", join_display(&feature.decisions));

        if matches!(args.depth, ShowDepth::Full | ShowDepth::Graph) && !feature.body.is_empty() {
            println!("\n{}", feature.body);
        }

        if matches!(args.depth, ShowDepth::Graph) {
            print_related(&registry, feature);
        }
    } else if let Some(story) = registry.stories.iter().find(|s| s.id.0 == args.id) {
        println!("Story: {} — {}", story.id.0, story.title);
        println!("Status: {}", story.status);
        println!("Features: {}", story.features.len());
        print_if_nonempty("  Features", join_display(&story.features));
        print_if_nonempty("Constraints", join_display(&story.constraints));
        if !story.body.is_empty() {
            println!("\n{}", story.body);
        }
    } else if let Some(decision) = registry.decisions.iter().find(|d| d.id.0 == args.id) {
        println!("Decision: {} — {}", decision.id.0, decision.title);
        println!("Status: {}", decision.status);
        println!("Date: {}", decision.date);
        print_if_nonempty("Features", join_display(&decision.features));
        print_if_nonempty("Constraints", join_display(&decision.constraints));
        if !decision.body.is_empty() {
            println!("\n{}", decision.body);
        }
    } else {
        println!("Entity '{}' not found.", args.id);
    }

    Ok(())
}

fn print_if_nonempty(label: &str, value: Option<String>) {
    if let Some(v) = value {
        println!("{label}: {v}");
    }
}

fn join_display(items: impl IntoIterator<Item = impl std::fmt::Display>) -> Option<String> {
    let mut iter = items.into_iter().peekable();
    if iter.peek().is_none() {
        None
    } else {
        Some(iter.map(|x| x.to_string()).collect::<Vec<_>>().join(", "))
    }
}

fn print_related(registry: &idd_fir_core::Registry, feature: &idd_fir_core::Feature) {
    println!("\nRelationships:");
    for dep_id in &feature.depends_on {
        if let Some(dep) = registry.feature(dep_id) {
            println!(
                "  ← depends on: {} [{}] {}",
                dep.id.0, dep.status, dep.title
            );
        }
    }
    for block_id in &feature.blocks {
        if let Some(blocked) = registry.feature(block_id) {
            println!(
                "  → blocks: {} [{}] {}",
                blocked.id.0, blocked.status, blocked.title
            );
        }
    }
    if let Some(story_id) = &feature.story {
        if let Some(story) = registry.story(story_id) {
            println!("  ↑ story: {} — {}", story.id.0, story.title);
        }
    }
}

fn cmd_promote(root: &Path, args: PromoteArgs) -> Result<()> {
    let (mut backend, registry) = load_registry(root)?;
    let (_fid, mut feature) = load_feature_mut(&mut backend, &registry, &args.id)?;

    let next = feature.status.next().ok_or_else(|| {
        anyhow::anyhow!(
            "Feature {} is in terminal status ({})",
            args.id,
            feature.status
        )
    })?;

    feature.promoted_from = Some(feature.status.to_string());
    feature.promoted_date = Some(chrono::Utc::now().naive_utc().date());
    feature.updated = Some(chrono::Utc::now().naive_utc().date());
    feature.status = next;

    backend
        .save_feature(&feature)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    println!("Promoted {} to {}", args.id, feature.status);

    Ok(())
}

fn cmd_status(root: &Path, args: StatusArgs) -> Result<()> {
    let (mut backend, registry) = load_registry(root)?;
    let (_fid, mut feature) = load_feature_mut(&mut backend, &registry, &args.id)?;

    feature.updated = Some(chrono::Utc::now().naive_utc().date());
    feature.status = parse_status(&args.status)?;

    backend
        .save_feature(&feature)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    println!("Set {} status to {}", args.id, feature.status);

    Ok(())
}

fn cmd_defer(root: &Path, args: DeferArgs) -> Result<()> {
    let (mut backend, registry) = load_registry(root)?;
    let (_fid, mut feature) = load_feature_mut(&mut backend, &registry, &args.id)?;

    let today = chrono::Utc::now().naive_utc().date();
    feature.updated = Some(today);
    feature.status = FeatureStatus::Deferred;
    feature.body = format!(
        "{}\n\n### Deferred: {today}\nReason: {}",
        feature.body, args.reason
    );

    backend
        .save_feature(&feature)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    println!("Deferred {}: {}", args.id, args.reason);

    Ok(())
}

fn cmd_abandon(root: &Path, args: AbandonArgs) -> Result<()> {
    let (mut backend, registry) = load_registry(root)?;
    let (fid, mut feature) = load_feature_mut(&mut backend, &registry, &args.id)?;

    let today = chrono::Utc::now().naive_utc().date();
    feature.updated = Some(today);
    feature.status = FeatureStatus::Abandoned;
    feature.body = format!(
        "{}\n\n### Abandoned: {today}\nReason: {}",
        feature.body, args.reason
    );

    backend
        .save_feature(&feature)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    backend
        .archive_feature(&fid)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    println!("Abandoned {}: {}", args.id, args.reason);

    Ok(())
}

fn cmd_link(root: &Path, args: LinkArgs) -> Result<()> {
    let (mut backend, registry) = load_registry(root)?;
    let (_fid, mut feature) = load_feature_mut(&mut backend, &registry, &args.id)?;

    dedup_push(
        &mut feature.depends_on,
        args.depends_on.into_iter().map(FeatureId),
    );
    dedup_push(&mut feature.blocks, args.blocks.into_iter().map(FeatureId));
    dedup_push(
        &mut feature.related,
        args.related.into_iter().map(FeatureId),
    );
    if let Some(story) = &args.story {
        feature.story = Some(StoryId(story.clone()));
    }
    dedup_push(
        &mut feature.constraints,
        args.constraint.into_iter().map(idd_dsl_core::DeclarationId),
    );

    feature.updated = Some(chrono::Utc::now().naive_utc().date());
    backend
        .save_feature(&feature)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    println!("Updated links for {}", args.id);

    Ok(())
}

fn cmd_decide(root: &Path, args: DecideArgs) -> Result<()> {
    let mut backend = load_backend(root)?;
    let mut registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;

    let id = registry.alloc_decision_id();
    let decision = idd_fir_core::Decision {
        id: id.clone(),
        title: args.title,
        date: chrono::Utc::now().naive_utc().date(),
        status: "proposed".into(),
        features: args.feature.into_iter().map(FeatureId).collect(),
        constraints: args
            .constraint
            .into_iter()
            .map(idd_dsl_core::DeclarationId)
            .collect(),
        body: String::new(),
    };

    backend
        .save_decision(&decision)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    println!("Created decision {id}: {}", decision.title);

    Ok(())
}

fn get_graph_features<'a>(registry: &'a Registry, args: &GraphArgs) -> Vec<&'a Feature> {
    if let Some(root_id) = &args.root {
        let fid = FeatureId(root_id.clone());
        registry
            .transitive_dependencies_depth(&fid, args.depth)
            .into_iter()
            .collect()
    } else if let Some(story) = &args.story {
        let sid = StoryId(story.clone());
        registry.features_by_story(&sid).into_iter().collect()
    } else {
        registry.active_features().into_iter().collect()
    }
}

fn print_feature(f: &Feature) {
    let deps = join_display(&f.depends_on);
    let blocks = join_display(&f.blocks);
    println!("{} [{}]", f.id.0, f.title);
    if let Some(d) = deps {
        println!("  ← depends on: {d}");
    }
    if let Some(b) = blocks {
        println!("  → blocks: {b}");
    }
}

fn cmd_graph(root: &Path, args: GraphArgs) -> Result<()> {
    let mut backend = load_backend(root)?;
    let registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;

    let features = get_graph_features(&registry, &args);
    for f in features {
        print_feature(f);
    }

    Ok(())
}

fn filter_by_scope(features: &mut Vec<&Feature>, scope: &str) {
    let scope_lower = scope.to_lowercase();
    features.retain(|f| {
        f.title.to_lowercase().contains(&scope_lower)
            || f.tags
                .iter()
                .any(|t| t.to_lowercase().contains(&scope_lower))
            || f.body.to_lowercase().contains(&scope_lower)
    });
}

fn filter_by_feature(features: &mut Vec<&Feature>, related_feature: &Feature) -> bool {
    let fid = related_feature.id.clone();
    let related_tags: std::collections::HashSet<_> = related_feature.tags.iter().collect();

    let any_related = features.iter().any(|f| {
        f.id == fid
            || f.depends_on.contains(&fid)
            || f.blocks.contains(&fid)
            || f.tags.iter().any(|t| related_tags.contains(t))
    });

    if any_related {
        features.retain(|f| {
            f.id == fid
                || f.depends_on.contains(&fid)
                || f.blocks.contains(&fid)
                || f.tags.iter().any(|t| related_tags.contains(t))
        });
    }
    any_related
}

fn format_feature_line(f: &Feature) -> String {
    let deps = join_display(&f.depends_on);
    let blocks = join_display(&f.blocks);

    let mut line = format!("- {} [{}] {}", f.id.0, f.status, f.title);
    if let Some(d) = deps {
        line.push_str(&format!(" — depends on: {d}"));
    }
    if let Some(b) = blocks {
        line.push_str(&format!(" — blocks: {b}"));
    }
    line
}

fn print_active_features(features: &[&Feature]) {
    println!("ACTIVE FEATURES:");
    for f in features {
        println!("{}", format_feature_line(f));
        print_if_nonempty("  Constraints", join_display(&f.constraints));
    }
}

fn print_wishes(registry: &Registry) {
    let wishes = registry.features_by_status(FeatureStatus::Wish);
    if !wishes.is_empty() {
        println!("\nFORWARD DESIGN CONTEXT:");
        for f in &wishes {
            println!(
                "- {} [wish] {} — consider this when designing related areas",
                f.id.0, f.title
            );
        }
    }
}

fn cmd_context(root: &Path, args: ContextArgs) -> Result<()> {
    let (_backend, registry) = load_registry(root)?;
    let mut active = registry.active_features();

    if let Some(scope) = &args.scope {
        filter_by_scope(&mut active, scope);
    }

    if let Some(for_feature) = &args.for_feature {
        let fid = FeatureId(for_feature.clone());
        if let Some(feature) = registry.feature(&fid) {
            filter_by_feature(&mut active, feature);
        }
    }

    if active.is_empty() {
        println!("No active features.");
        return Ok(());
    }

    print_active_features(&active);
    print_wishes(&registry);

    Ok(())
}

fn cmd_check(root: &Path, _args: CheckArgs) -> Result<()> {
    let mut backend = load_backend(root)?;
    let registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;

    let findings =
        idd_fir_core::IntegrityChecker::check_all(&registry, &std::collections::HashSet::new());

    if findings.is_empty() {
        println!("All checks passed.");
        return Ok(());
    }

    for finding in &findings {
        let severity = match finding.severity {
            idd_fir_core::FindingSeverity::Error => "ERROR",
            idd_fir_core::FindingSeverity::Warning => "WARN",
        };
        println!("[{severity}] {}: {}", finding.entity, finding.description);
    }

    if findings
        .iter()
        .any(|f| matches!(f.severity, idd_fir_core::FindingSeverity::Error))
    {
        anyhow::bail!("Integrity check failed");
    }

    Ok(())
}

fn update_basic_fields(feature: &mut Feature, args: &UpdateArgs) -> Result<()> {
    if let Some(title) = &args.title {
        feature.title = title.clone();
    }
    if let Some(status) = &args.status {
        feature.status = parse_status(status)?;
    }
    if args.set_tags {
        feature.tags = args.tag.clone();
    } else if !args.tag.is_empty() {
        dedup_push(&mut feature.tags, args.tag.iter().cloned());
    }
    if let Some(body) = &args.body {
        feature.body = body.clone();
    }
    if let Some(append) = &args.append_body {
        if !feature.body.is_empty() {
            feature.body.push('\n');
        }
        feature.body.push_str(append);
    }
    Ok::<(), anyhow::Error>(())
}

fn update_metadata_fields(feature: &mut Feature, args: &UpdateArgs) {
    if let Some(priority) = &args.priority {
        feature.priority = Some(priority.clone());
    }
    if let Some(effort) = &args.effort {
        feature.effort_estimate = Some(effort.clone());
    }
    if let Some(source) = &args.source {
        feature.source = Some(source.clone());
    }
}

fn update_relationships(feature: &mut Feature, args: &UpdateArgs) {
    dedup_push(
        &mut feature.depends_on,
        args.add_depends_on.iter().map(|s| FeatureId(s.clone())),
    );
    dedup_push(
        &mut feature.blocks,
        args.add_blocks.iter().map(|s| FeatureId(s.clone())),
    );
    dedup_push(
        &mut feature.related,
        args.add_related.iter().map(|s| FeatureId(s.clone())),
    );
    dedup_push(
        &mut feature.constraints,
        args.add_constraint
            .iter()
            .map(|s| idd_dsl_core::DeclarationId(s.clone())),
    );
}

fn cmd_update<B: FirBackend>(backend: &mut B, args: UpdateArgs) -> Result<()> {
    let registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;
    let (_fid, mut feature) = load_feature_mut(backend, &registry, &args.id)?;

    update_basic_fields(&mut feature, &args)?;
    update_metadata_fields(&mut feature, &args);
    update_relationships(&mut feature, &args);

    feature.updated = Some(chrono::Utc::now().naive_utc().date());
    backend
        .save_feature(&feature)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    println!("Updated {}", args.id);

    Ok(())
}

fn cmd_search<B: FirBackend>(backend: &B, args: SearchArgs) -> Result<()> {
    let results = backend.search(&args.query);

    if results.is_empty() {
        println!("No results for \"{}\".", args.query);
        return Ok(());
    }

    println!("{} result(s) for \"{}\":\n", results.len(), args.query);
    for r in &results {
        let kind_label = match r.kind {
            idd_fir_core::SearchKind::Feature => "FIR",
            idd_fir_core::SearchKind::Story => "STORY",
            idd_fir_core::SearchKind::Decision => "DEC",
        };
        println!("[{kind_label}] {} — {}", r.id, r.title);
        if !r.excerpt.is_empty() {
            println!("  {}", r.excerpt.chars().take(120).collect::<String>());
        }
        println!();
    }

    Ok(())
}

fn add_note_to_body(feature: &mut Feature, note: &str) -> String {
    let today = chrono::Utc::now().naive_utc().date();
    let heading = if !feature.body.is_empty() && !feature.body.ends_with('\n') {
        format!("\n\n### {today} — {note}", note = note)
    } else {
        format!("### {today} — {note}", note = note)
    };
    feature.body.push_str(&heading);
    feature.updated = Some(today);
    heading
}

fn cmd_note<B: FirBackend>(backend: &mut B, args: NoteArgs) -> Result<()> {
    let registry = backend.load_all().map_err(|e| anyhow::anyhow!("{e}"))?;
    let (_fid, mut feature) = load_feature_mut(backend, &registry, &args.id)?;

    if let Some(ref_) = &args.ref_ {
        feature.conversations.push(idd_fir_core::Conversation {
            date: chrono::Utc::now().naive_utc().date(),
            ref_: ref_.clone(),
        });
    }

    let _ = add_note_to_body(&mut feature, &args.note);
    backend
        .save_feature(&feature)
        .map_err(|e| anyhow::anyhow!("{e}"))?;
    println!("Added note to {}: {}", args.id, args.note);

    Ok(())
}

