                | "in-progress" | "verifying" | "done" | "abandoned" | "deferred"
            );
            let mut backend = seed_backend();
            let result = cmd_update(&mut backend, UpdateArgs {
                id: "FIR-0".into(),
                status: Some(status.clone()),
                ..Default::default()
            });
            if valid {
                prop_assert!(result.is_ok());
            } else {
                prop_assert!(result.is_err());
            }
        }
