        #[test]
        fn note_empty_body_no_leading_newlines(
            note_text in "[a-zA-Z ]{5,20}",
        ) {
            let mut backend = seed_backend();
            cmd_update(&mut backend, UpdateArgs {
                id: "FIR-0".into(),
                body: Some("".into()),
                ..Default::default()
            }).unwrap();
            cmd_note(&mut backend, NoteArgs {
                id: "FIR-0".into(),
