                ref_: None,
            }).unwrap();

            let f = backend.load_feature(&FeatureId::new(0)).unwrap();
            prop_assert!(!f.body.starts_with('\n'));
            prop_assert_eq!(f.body, format!("### {} — {note_text}", chrono::Utc::now().naive_utc().date()));
        }
    }

    // ── PBT: negative — nonexistent entity ────────────────

    proptest! {
        #[test]
        fn update_nonexistent_always_fails(
            _id in "[a-zA-Z0-9-]{1,20}",
