use crate::model::{FeatureId, Registry};
use idd_dsl_core::DeclarationId;
use std::collections::HashSet;

#[derive(Debug, Clone)]
pub struct IntegrityFinding {
    pub severity: Severity,
    pub entity: String,
    pub description: String,
}

#[derive(Debug, Clone)]
pub enum Severity {
    Error,
    Warning,
}

pub struct IntegrityChecker;

impl IntegrityChecker {
    pub fn check_all(
        registry: &Registry,
        known_constraints: &HashSet<DeclarationId>,
    ) -> Vec<IntegrityFinding> {
        let mut findings = Vec::new();
        Self::check_referential(registry, &mut findings);
        Self::check_cycles(registry, &mut findings);
        Self::check_orphans(registry, &mut findings);
        Self::check_duplicate_feature_ids(registry, &mut findings);
        Self::check_duplicate_story_ids(registry, &mut findings);
        Self::check_duplicate_decision_ids(registry, &mut findings);
        Self::check_constraint_references(registry, known_constraints, &mut findings);
        findings
    }

    fn check_referential(registry: &Registry, findings: &mut Vec<IntegrityFinding>) {
        for feature in &registry.features {
            for dep_id in &feature.depends_on {
                if registry.feature(dep_id).is_none() {
                    findings.push(IntegrityFinding {
                        severity: Severity::Error,
                        entity: feature.id.0.clone(),
                        description: format!("depends on unknown feature {}", dep_id.0),
                    });
                }
            }
            for block_id in &feature.blocks {
                if registry.feature(block_id).is_none() {
                    findings.push(IntegrityFinding {
                        severity: Severity::Error,
                        entity: feature.id.0.clone(),
                        description: format!("blocks unknown feature {}", block_id.0),
                    });
                }
            }
            if let Some(story_id) = &feature.story {
                if registry.story(story_id).is_none() {
                    findings.push(IntegrityFinding {
                        severity: Severity::Error,
                        entity: feature.id.0.clone(),
                        description: format!("references unknown story {}", story_id.0),
                    });
                }
            }
            for dec_id in &feature.decisions {
                if registry.decision(dec_id).is_none() {
                    findings.push(IntegrityFinding {
                        severity: Severity::Warning,
                        entity: feature.id.0.clone(),
                        description: format!("references unknown decision {}", dec_id.0),
                    });
                }
            }
        }
    }

    fn check_cycles(registry: &Registry, findings: &mut Vec<IntegrityFinding>) {
        for feature in &registry.features {
            let mut visited = std::collections::HashSet::new();
            if Self::has_cycle(registry, &feature.id, &mut visited) {
                findings.push(IntegrityFinding {
                    severity: Severity::Error,
                    entity: feature.id.0.clone(),
                    description: "dependency cycle detected".into(),
                });
            }
        }
    }

    fn has_cycle(
        registry: &Registry,
        id: &FeatureId,
        visited: &mut std::collections::HashSet<FeatureId>,
    ) -> bool {
        if !visited.insert(id.clone()) {
            return true;
        }
        let Some(feature) = registry.feature(id) else {
            return false;
        };
        for dep_id in &feature.depends_on {
            if Self::has_cycle(registry, dep_id, visited) {
                return true;
            }
        }
        visited.remove(id);
        false
    }

    fn check_orphans(registry: &Registry, findings: &mut Vec<IntegrityFinding>) {
        for feature in &registry.features {
            if feature.story.is_none() && !feature.tags.is_empty() {
                findings.push(IntegrityFinding {
                    severity: Severity::Warning,
                    entity: feature.id.0.clone(),
                    description: "feature has no parent story".into(),
                });
            }
        }
    }

    fn check_duplicate_ids(
        entities: impl Iterator<Item = (String, String)>,
        kind: &str,
        findings: &mut Vec<IntegrityFinding>,
    ) {
        let mut seen = std::collections::HashMap::new();
        for (id, title) in entities {
            if let Some(prev) = seen.insert(id.clone(), title) {
                findings.push(IntegrityFinding {
                    severity: Severity::Error,
                    entity: id,
                    description: format!("duplicate {kind} ID (also used by: \"{prev}\")"),
                });
            }
        }
    }

    fn check_duplicate_feature_ids(registry: &Registry, findings: &mut Vec<IntegrityFinding>) {
        Self::check_duplicate_ids(
            registry
                .features
                .iter()
                .map(|f| (f.id.0.clone(), f.title.clone())),
            "feature",
            findings,
        );
    }

    fn check_duplicate_story_ids(registry: &Registry, findings: &mut Vec<IntegrityFinding>) {
        Self::check_duplicate_ids(
            registry
                .stories
                .iter()
                .map(|s| (s.id.0.clone(), s.title.clone())),
            "story",
            findings,
        );
    }

    fn check_duplicate_decision_ids(registry: &Registry, findings: &mut Vec<IntegrityFinding>) {
        Self::check_duplicate_ids(
            registry
                .decisions
                .iter()
                .map(|d| (d.id.0.clone(), d.title.clone())),
            "decision",
            findings,
        );
    }

    fn check_constraint_references(
        registry: &Registry,
        known: &HashSet<DeclarationId>,
        findings: &mut Vec<IntegrityFinding>,
    ) {
        let feature_constraints = registry
            .features
            .iter()
            .flat_map(|f| f.constraints.iter().map(move |c| (&f.id.0, c)));
        let story_constraints = registry
            .stories
            .iter()
            .flat_map(|s| s.constraints.iter().map(move |c| (&s.id.0, c)));

        for (entity_id, cid) in feature_constraints.chain(story_constraints) {
            if !known.contains(cid) {
                findings.push(IntegrityFinding {
                    severity: Severity::Error,
                    entity: entity_id.clone(),
                    description: format!("references unknown constraint \"{}\"", cid.0),
                });
            }
        }
    }
}

