        }
    }

    #[test]
    fn duplicate_feature_ids_detected() {
        let mut registry = Registry::new();
        registry.features.push(make_feature("FIR-1"));
        let mut dup = make_feature("FIR-1");
        dup.title = "Duplicate".into();
        registry.features.push(dup);

        let findings = IntegrityChecker::check_all(&registry, &HashSet::new());
        let dup_findings: Vec<_> = findings
            .iter()
            .filter(|f| f.description.contains("duplicate feature ID"))
            .collect();
        assert_eq!(dup_findings.len(), 1);
    }

    #[test]
    fn duplicate_story_ids_detected() {
        let mut registry = Registry::new();
        registry.stories.push(Story {
