            id: crate::model::StoryId("STORY-1".into()),
            title: "Story B".into(),
            status: "wish".into(),
            created: chrono::NaiveDate::from_ymd_opt(2026, 1, 1).unwrap(),
            features: Vec::new(),
            constraints: Vec::new(),
            tags: Vec::new(),
            body: String::new(),
        });

        let findings = IntegrityChecker::check_all(&registry, &HashSet::new());
        let dup_findings: Vec<_> = findings
            .iter()
            .filter(|f| f.description.contains("duplicate story ID"))
            .collect();
        assert_eq!(dup_findings.len(), 1);
    }

    #[test]
    fn duplicate_decision_ids_detected() {
        let mut registry = Registry::new();
        registry.decisions.push(Decision {
            id: crate::model::DecisionId("DEC-1".into()),
            title: "Decision A".into(),
            date: chrono::NaiveDate::from_ymd_opt(2026, 1, 1).unwrap(),
            status: "proposed".into(),
            features: Vec::new(),
            constraints: Vec::new(),
            body: String::new(),
        });
        registry.decisions.push(Decision {
            id: crate::model::DecisionId("DEC-1".into()),
            title: "Decision B".into(),
            date: chrono::NaiveDate::from_ymd_opt(2026, 1, 1).unwrap(),
            status: "proposed".into(),
            features: Vec::new(),
            constraints: Vec::new(),
            body: String::new(),
        });

        let findings = IntegrityChecker::check_all(&registry, &HashSet::new());
        let dup_findings: Vec<_> = findings
            .iter()
            .filter(|f| f.description.contains("duplicate decision ID"))
            .collect();
        assert_eq!(dup_findings.len(), 1);
    }

    #[test]
    fn no_false_positives_for_unique_ids() {
        let mut registry = Registry::new();
        registry.features.push(make_feature("FIR-1"));
        registry.features.push(make_feature("FIR-2"));
        registry.features.push(make_feature("FIR-3"));

        let findings = IntegrityChecker::check_all(&registry, &HashSet::new());
        let dup_findings: Vec<_> = findings
            .iter()
            .filter(|f| f.description.contains("duplicate"))
            .collect();
        assert!(dup_findings.is_empty());
    }

    #[test]
    fn unknown_constraint_references_detected() {
        let mut registry = Registry::new();
        let mut feature = make_feature("FIR-1");
        feature.constraints = vec![
            DeclarationId("known-constraint".into()),
            DeclarationId("ghost-constraint".into()),
        ];
        registry.features.push(feature);

        let known: HashSet<DeclarationId> = [DeclarationId("known-constraint".into())]
            .into_iter()
            .collect();

        let findings = IntegrityChecker::check_all(&registry, &known);
        let missing: Vec<_> = findings
            .iter()
            .filter(|f| f.description.contains("unknown constraint"))
            .collect();
        assert_eq!(missing.len(), 1);
        assert!(missing[0].description.contains("ghost-constraint"));
    }

    #[test]
    fn valid_constraint_references_pass() {
        let mut registry = Registry::new();
        let mut feature = make_feature("FIR-1");
        feature.constraints = vec![
            DeclarationId("constraint-a".into()),
            DeclarationId("constraint-b".into()),
        ];
        registry.features.push(feature);

        let known: HashSet<DeclarationId> = [
            DeclarationId("constraint-a".into()),
            DeclarationId("constraint-b".into()),
        ]
        .into_iter()
        .collect();

        let findings = IntegrityChecker::check_all(&registry, &known);
        let constraint_findings: Vec<_> = findings
            .iter()
            .filter(|f| f.description.contains("unknown constraint"))
            .collect();
        assert!(constraint_findings.is_empty());
    }
}

