#[derive(Default)]
pub struct InMemoryBackend {
    registry: Registry,
}

impl InMemoryBackend {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn with_registry(registry: Registry) -> Self {
        Self { registry }
    }

    pub fn registry(&self) -> &Registry {
        &self.registry
    }
}

impl FirBackend for InMemoryBackend {
    fn load_all(&mut self) -> Result<Registry> {
        Ok(self.registry.clone())
    }

    fn load_feature(&self, id: &FeatureId) -> Result<Feature> {
        self.registry
            .feature(id)
            .cloned()
            .ok_or_else(|| BackendError::NotFound(format!("feature {id}")))
    }

    fn save_feature(&mut self, feature: &Feature) -> Result<()> {
        if let Some(existing) = self
            .registry
            .features
            .iter_mut()
            .find(|f| f.id == feature.id)
        {
            *existing = feature.clone();
        } else {
            self.registry.features.push(feature.clone());
        }
        Ok(())
    }

    fn load_story(&self, id: &StoryId) -> Result<Story> {
        self.registry
            .story(id)
            .cloned()
            .ok_or_else(|| BackendError::NotFound(format!("story {id}")))
    }

    fn save_story(&mut self, story: &Story) -> Result<()> {
        if let Some(existing) = self.registry.stories.iter_mut().find(|s| s.id == story.id) {
            *existing = story.clone();
        } else {
            self.registry.stories.push(story.clone());
        }
        Ok(())
    }

    fn load_decision(&self, id: &DecisionId) -> Result<Decision> {
        self.registry
            .decision(id)
            .cloned()
            .ok_or_else(|| BackendError::NotFound(format!("decision {id}")))
    }

    fn save_decision(&mut self, decision: &Decision) -> Result<()> {
        if let Some(existing) = self
            .registry
            .decisions
            .iter_mut()
            .find(|d| d.id == decision.id)
        {
            *existing = decision.clone();
        } else {
            self.registry.decisions.push(decision.clone());
        }
        Ok(())
    }

    fn next_id(&self, kind: IdKind) -> String {
        match kind {
            IdKind::Feature => FeatureId::new(self.registry.next_feature_id).0,
            IdKind::Story => StoryId::new(self.registry.next_story_id).0,
            IdKind::Decision => DecisionId::new(self.registry.next_decision_id).0,
        }
    }

    fn search(&self, query: &str) -> Vec<SearchResult> {
        let q = query.to_lowercase();
        let mut results = Vec::new();

        for f in &self.registry.features {
            if f.title.to_lowercase().contains(&q) || f.body.to_lowercase().contains(&q) {
                results.push(SearchResult {
                    id: f.id.0.clone(),
                    kind: SearchKind::Feature,
                    title: f.title.clone(),
                    excerpt: f.body.chars().take(200).collect(),
                });
            }
        }

        for s in &self.registry.stories {
            if s.title.to_lowercase().contains(&q) || s.body.to_lowercase().contains(&q) {
                results.push(SearchResult {
                    id: s.id.0.clone(),
                    kind: SearchKind::Story,
                    title: s.title.clone(),
                    excerpt: s.body.chars().take(200).collect(),
                });
            }
        }

        for d in &self.registry.decisions {
            if d.title.to_lowercase().contains(&q) || d.body.to_lowercase().contains(&q) {
                results.push(SearchResult {
                    id: d.id.0.clone(),
                    kind: SearchKind::Decision,
                    title: d.title.clone(),
                    excerpt: d.body.chars().take(200).collect(),
                });
            }
        }

        results
    }
}

