// ── Status ──────────────────────────────────────────────────

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum FeatureStatus {
    Wish,
    Exploring,
    Scoping,
    Designing,
    Ready,
    InProgress,
    Verifying,
    Done,
    Abandoned,
    Deferred,
}

impl FeatureStatus {
    pub fn next(&self) -> Option<Self> {
        match self {
            FeatureStatus::Wish => Some(FeatureStatus::Exploring),
            FeatureStatus::Exploring => Some(FeatureStatus::Scoping),
            FeatureStatus::Scoping => Some(FeatureStatus::Designing),
            FeatureStatus::Designing => Some(FeatureStatus::Ready),
            FeatureStatus::Ready => Some(FeatureStatus::InProgress),
            FeatureStatus::InProgress => Some(FeatureStatus::Verifying),
            FeatureStatus::Verifying => Some(FeatureStatus::Done),
            FeatureStatus::Done | FeatureStatus::Abandoned | FeatureStatus::Deferred => None,
        }
    }

    pub const fn is_terminal(&self) -> bool {
        matches!(
            self,
            FeatureStatus::Done | FeatureStatus::Abandoned | FeatureStatus::Deferred
        )
    }

    pub const fn is_active(&self) -> bool {
        matches!(
            self,
            FeatureStatus::Designing
                | FeatureStatus::Ready
                | FeatureStatus::InProgress
                | FeatureStatus::Verifying
        )
    }
}

impl std::fmt::Display for FeatureStatus {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        let s = match self {
            FeatureStatus::Wish => "wish",
            FeatureStatus::Exploring => "exploring",
            FeatureStatus::Scoping => "scoping",
            FeatureStatus::Designing => "designing",
            FeatureStatus::Ready => "ready",
            FeatureStatus::InProgress => "in-progress",
            FeatureStatus::Verifying => "verifying",
            FeatureStatus::Done => "done",
            FeatureStatus::Abandoned => "abandoned",
            FeatureStatus::Deferred => "deferred",
        };
        write!(f, "{s}")
    }
}

