// ── Registry ────────────────────────────────────────────────

#[derive(Debug, Clone, Default)]
pub struct Registry {
    pub features: Vec<Feature>,
    pub stories: Vec<Story>,
    pub decisions: Vec<Decision>,
    pub next_feature_id: u64,
    pub next_story_id: u64,
    pub next_decision_id: u64,
}

impl Registry {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn feature(&self, id: &FeatureId) -> Option<&Feature> {
        self.features.iter().find(|f| &f.id == id)
    }

    pub fn feature_mut(&mut self, id: &FeatureId) -> Option<&mut Feature> {
        self.features.iter_mut().find(|f| &f.id == id)
    }

    pub fn story(&self, id: &StoryId) -> Option<&Story> {
        self.stories.iter().find(|s| &s.id == id)
    }

    pub fn decision(&self, id: &DecisionId) -> Option<&Decision> {
        self.decisions.iter().find(|d| &d.id == id)
    }

    pub fn alloc_feature_id(&mut self) -> FeatureId {
        let id = FeatureId::new(self.next_feature_id);
        self.next_feature_id += 1;
        id
    }

    pub fn alloc_story_id(&mut self) -> StoryId {
        let id = StoryId::new(self.next_story_id);
        self.next_story_id += 1;
        id
    }

    pub fn alloc_decision_id(&mut self) -> DecisionId {
        let id = DecisionId::new(self.next_decision_id);
        self.next_decision_id += 1;
        id
    }

    pub fn active_features(&self) -> Vec<&Feature> {
        self.features
            .iter()
            .filter(|f| !f.status.is_terminal())
            .collect()
    }

    pub fn features_by_status(&self, status: FeatureStatus) -> Vec<&Feature> {
        self.features
            .iter()
            .filter(|f| f.status == status)
            .collect()
    }

    pub fn features_by_tag(&self, tag: &str) -> Vec<&Feature> {
        self.features
            .iter()
            .filter(|f| f.tags.iter().any(|t| t == tag))
            .collect()
    }

    pub fn features_by_story(&self, story_id: &StoryId) -> Vec<&Feature> {
        self.features
            .iter()
            .filter(|f| f.story.as_ref() == Some(story_id))
            .collect()
    }

    pub fn features_blocking(&self, feature_id: &FeatureId) -> Vec<&Feature> {
        self.features
            .iter()
            .filter(|f| f.blocks.iter().any(|b| b == feature_id))
            .collect()
    }

    pub fn transitive_dependencies(&self, feature_id: &FeatureId) -> Vec<&Feature> {
        self.transitive_dependencies_depth(feature_id, usize::MAX)
    }

    pub fn transitive_dependencies_depth(
        &self,
        feature_id: &FeatureId,
        max_depth: usize,
    ) -> Vec<&Feature> {
        let mut visited = std::collections::HashSet::new();
        let mut result = Vec::new();
        self._collect_deps(feature_id, &mut visited, &mut result, max_depth, 0);
        result
    }

    fn _collect_deps<'a>(
        &'a self,
        feature_id: &FeatureId,
        visited: &mut std::collections::HashSet<FeatureId>,
        result: &mut Vec<&'a Feature>,
        max_depth: usize,
        depth: usize,
    ) {
        if !visited.insert(feature_id.clone()) || depth >= max_depth {
            return;
        }
        let Some(feature) = self.feature(feature_id) else {
            return;
        };
        for dep_id in &feature.depends_on {
            if let Some(dep) = self.feature(dep_id) {
                result.push(dep);
                self._collect_deps(dep_id, visited, result, max_depth, depth + 1);
            }
        }
    }
}

