#[cfg(test)]
mod tests {
    use super::*;
    use proptest::prelude::*;

    // ── FeatureStatus state machine invariants ──────────────

    proptest! {
        #[test]
        fn status_next_is_monotonic(status in prop_oneof![
            Just(FeatureStatus::Wish),
            Just(FeatureStatus::Exploring),
            Just(FeatureStatus::Scoping),
            Just(FeatureStatus::Designing),
            Just(FeatureStatus::Ready),
            Just(FeatureStatus::InProgress),
            Just(FeatureStatus::Verifying),
        ]) {
            let next = status.next().unwrap();
            prop_assert!(matches!(
                (status, next),
                (FeatureStatus::Wish, FeatureStatus::Exploring)
                | (FeatureStatus::Exploring, FeatureStatus::Scoping)
                | (FeatureStatus::Scoping, FeatureStatus::Designing)
                | (FeatureStatus::Designing, FeatureStatus::Ready)
                | (FeatureStatus::Ready, FeatureStatus::InProgress)
                | (FeatureStatus::InProgress, FeatureStatus::Verifying)
                | (FeatureStatus::Verifying, FeatureStatus::Done),
            ));
        }

        #[test]
        fn terminal_statuses_have_no_next(status in prop_oneof![
            Just(FeatureStatus::Done),
            Just(FeatureStatus::Abandoned),
            Just(FeatureStatus::Deferred),
        ]) {
            prop_assert!(status.next().is_none());
        }

        #[test]
        fn terminal_and_active_are_mutually_exclusive(status in prop_oneof![
            Just(FeatureStatus::Wish),
            Just(FeatureStatus::Exploring),
            Just(FeatureStatus::Scoping),
            Just(FeatureStatus::Designing),
            Just(FeatureStatus::Ready),
            Just(FeatureStatus::InProgress),
            Just(FeatureStatus::Verifying),
            Just(FeatureStatus::Done),
            Just(FeatureStatus::Abandoned),
            Just(FeatureStatus::Deferred),
        ]) {
            prop_assert!(!(status.is_terminal() && status.is_active()));
        }

        #[test]
        fn status_display_roundtrip(status in prop_oneof![
            Just(FeatureStatus::Wish),
            Just(FeatureStatus::Exploring),
            Just(FeatureStatus::Scoping),
            Just(FeatureStatus::Designing),
            Just(FeatureStatus::Ready),
            Just(FeatureStatus::InProgress),
            Just(FeatureStatus::Verifying),
            Just(FeatureStatus::Done),
            Just(FeatureStatus::Abandoned),
            Just(FeatureStatus::Deferred),
        ]) {
            let s = status.to_string();
            prop_assert!(matches!(
