enum StaleMode {
    Stale { days: u32, now: chrono::NaiveDate },
    Recent { days: u32, now: chrono::NaiveDate },
}

/// Composable query builder over a [`Registry`].
///
/// Accumulates filter predicates via a builder API, then resolves them
/// in a single pass over the feature set via [`resolve`](Self::resolve).
///
/// # Example
/// ```ignore
/// let features = Query::new(&registry)
///     .status(vec![FeatureStatus::InProgress, FeatureStatus::Ready])
///     .tag("backend")
///     .stale_days(14)
///     .resolve();
/// ```
pub struct Query<'a> {
    registry: &'a Registry,
    statuses: Vec<FeatureStatus>,
    tag: Option<String>,
    story: Option<StoryId>,
    blocks: Option<FeatureId>,
    constraint: Option<String>,
    depends_on: Option<FeatureId>,
    stale_mode: Option<StaleMode>,
}

impl<'a> Query<'a> {
    pub fn new(registry: &'a Registry) -> Self {
        Self {
            registry,
            statuses: Vec::new(),
            tag: None,
            story: None,
            blocks: None,
            constraint: None,
            depends_on: None,
            stale_mode: None,
        }
    }

    /// Filter to features matching any of the given statuses.
    pub fn status(mut self, statuses: Vec<FeatureStatus>) -> Self {
        self.statuses = statuses;
        self
    }

    /// Filter to features containing the given tag.
    pub fn tag(mut self, tag: impl Into<String>) -> Self {
        self.tag = Some(tag.into());
        self
    }

    /// Filter to features linked to the given story.
    pub fn story(mut self, story_id: StoryId) -> Self {
        self.story = Some(story_id);
        self
    }

    /// Filter to features that block the given feature.
    pub fn blocks(mut self, feature_id: FeatureId) -> Self {
        self.blocks = Some(feature_id);
        self
    }

    /// Filter to features associated with the given constraint ID.
    pub fn constraint(mut self, constraint_id: impl Into<String>) -> Self {
        self.constraint = Some(constraint_id.into());
        self
    }

    /// Filter to features that depend on the given feature.
    pub fn depends_on(mut self, feature_id: FeatureId) -> Self {
        self.depends_on = Some(feature_id);
        self
    }

    /// Filter to features not updated within the given number of days.
    pub fn stale_days(mut self, days: u32, now: chrono::NaiveDate) -> Self {
        self.stale_mode = Some(StaleMode::Stale { days, now });
        self
    }

    /// Filter to features updated within the given number of days.
    pub fn recent_days(mut self, days: u32, now: chrono::NaiveDate) -> Self {
        self.stale_mode = Some(StaleMode::Recent { days, now });
        self
    }

    /// Resolve all accumulated predicates in a single pass.
    pub fn resolve(self) -> Vec<&'a Feature> {
        let threshold = self.stale_mode.map(|m| match m {
            StaleMode::Stale { days, now } => (now - chrono::Duration::days(days as i64), false),
            StaleMode::Recent { days, now } => (now - chrono::Duration::days(days as i64), true),
        });

        self.registry
            .features
            .iter()
            .filter(|f| {
                if !self.statuses.is_empty() && !self.statuses.contains(&f.status) {
                    return false;
                }
                if let Some(tag) = &self.tag {
                    if !f.tags.iter().any(|t| t == tag) {
                        return false;
                    }
                }
                if let Some(story_id) = &self.story {
                    if f.story.as_ref() != Some(story_id) {
                        return false;
                    }
                }
                if let Some(feature_id) = &self.blocks {
                    if !f.blocks.iter().any(|b| b == feature_id) {
                        return false;
                    }
                }
                if let Some(constraint_id) = &self.constraint {
                    if !f.constraints.iter().any(|c| c.0 == *constraint_id) {
                        return false;
                    }
                }
                if let Some(feature_id) = &self.depends_on {
                    if !f.depends_on.contains(feature_id) {
                        return false;
                    }
                }
                if let Some((threshold, keep_recent)) = threshold {
                    let last_activity = f.updated.unwrap_or(f.created);
                    if keep_recent {
                        if last_activity < threshold {
                            return false;
                        }
                    } else if last_activity >= threshold {
                        return false;
                    }
                }
                true
            })
            .collect()
    }
}

use idd_fir_core::{
    backend::{
        BackendError, FirBackend, IdKind, Result as BackendResult, SearchKind, SearchResult,
    },
    Config, Decision, DecisionId, Feature, FeatureId, Registry, Story, StoryId,
};
use std::path::{Path, PathBuf};

use crate::frontmatter::{parse_frontmatter, render_frontmatter};

fn write_md<T: serde::Serialize>(path: &Path, frontmatter: &T, body: &str) -> BackendResult<()> {
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(BackendError::Io)?;
    }
    let content =
        render_frontmatter(frontmatter, body).map_err(|e| BackendError::Parse(e.to_string()))?;
    let tmp = path.with_extension("md.tmp");
    std::fs::write(&tmp, &content).map_err(BackendError::Io)?;
    std::fs::rename(&tmp, path).map_err(BackendError::Io)?;
    Ok(())
}

fn read_md<T: serde::de::DeserializeOwned>(path: &Path) -> BackendResult<(T, String)> {
    let content = std::fs::read_to_string(path).map_err(|e| {
        if e.kind() == std::io::ErrorKind::NotFound {
            BackendError::NotFound(format!("{:?}", path))
        } else {
            BackendError::Io(e)
        }
    })?;
    let parsed =
        parse_frontmatter::<T>(&content).map_err(|e| BackendError::Parse(e.to_string()))?;
    Ok((parsed.frontmatter, parsed.body))
}

pub struct FileBackend {
    base_path: PathBuf,
    registry: Registry,
}

impl FileBackend {
    pub fn new(base_path: PathBuf) -> BackendResult<Self> {
        let mut backend = Self {
            base_path,
            registry: Registry::new(),
        };
        backend.registry = backend.load_all()?;
        Ok(backend)
    }

    fn fir_path(&self) -> PathBuf {
        self.base_path.join(".fir")
    }

    fn feature_path(&self, id: &FeatureId) -> PathBuf {
        self.fir_path()
            .join("features")
            .join(format!("{}.md", id.0))
    }

    fn story_path(&self, id: &StoryId) -> PathBuf {
        self.fir_path().join("stories").join(format!("{}.md", id.0))
    }

    fn decision_path(&self, id: &DecisionId) -> PathBuf {
        self.fir_path()
            .join("decisions")
            .join(format!("{}.md", id.0))
    }

    fn ensure_dirs(&self) -> std::io::Result<()> {
        let fir = self.fir_path();
        std::fs::create_dir_all(fir.join("features"))?;
        std::fs::create_dir_all(fir.join("stories"))?;
        std::fs::create_dir_all(fir.join("decisions"))?;
        std::fs::create_dir_all(fir.join("archive"))?;
        Ok(())
    }

    fn load_config(&self) -> BackendResult<Config> {
        let config_path = self.fir_path().join("config.toml");
        let content = std::fs::read_to_string(&config_path).map_err(|e| {
            if e.kind() == std::io::ErrorKind::NotFound {
                BackendError::NotFound(format!("config at {:?}", config_path))
            } else {
                BackendError::Io(e)
            }
        })?;
        toml::from_str(&content).map_err(|e| BackendError::Parse(e.to_string()))
    }

    pub fn archive_feature(&self, id: &FeatureId) -> BackendResult<()> {
        let src = self.feature_path(id);
        self.ensure_dirs().map_err(BackendError::Io)?;
        let dst = self.fir_path().join("archive").join(format!("{}.md", id.0));
        if src.exists() {
            std::fs::rename(&src, &dst).map_err(BackendError::Io)?;
        }
        Ok(())
    }
}

impl FirBackend for FileBackend {
    fn load_all(&mut self) -> BackendResult<Registry> {
        let config = match self.load_config() {
            Ok(c) => c,
            Err(BackendError::NotFound(_)) => Config::default(),
            Err(e) => return Err(e),
        };

        let mut registry = Registry {
            next_feature_id: config.counters.next_feature,
            next_story_id: config.counters.next_story,
            next_decision_id: config.counters.next_decision,
            ..Registry::new()
        };

        let features_dir = self.fir_path().join("features");
        if features_dir.exists() {
            for entry in std::fs::read_dir(&features_dir).map_err(BackendError::Io)? {
                let entry = entry.map_err(BackendError::Io)?;
                let path = entry.path();
                if path.extension().and_then(|e| e.to_str()) == Some("md") {
                    let (feature, body) = read_md::<Feature>(&path)?;
                    let mut feature = feature;
                    feature.body = body;
                    registry.features.push(feature);
                }
            }
        }

        let stories_dir = self.fir_path().join("stories");
        if stories_dir.exists() {
            for entry in std::fs::read_dir(&stories_dir).map_err(BackendError::Io)? {
                let entry = entry.map_err(BackendError::Io)?;
                let path = entry.path();
                if path.extension().and_then(|e| e.to_str()) == Some("md") {
                    let (story, body) = read_md::<Story>(&path)?;
                    let mut story = story;
                    story.body = body;
                    registry.stories.push(story);
                }
            }
        }

        let decisions_dir = self.fir_path().join("decisions");
        if decisions_dir.exists() {
            for entry in std::fs::read_dir(&decisions_dir).map_err(BackendError::Io)? {
                let entry = entry.map_err(BackendError::Io)?;
                let path = entry.path();
                if path.extension().and_then(|e| e.to_str()) == Some("md") {
                    let (decision, body) = read_md::<Decision>(&path)?;
                    let mut decision = decision;
                    decision.body = body;
                    registry.decisions.push(decision);
                }
            }
        }

        Ok(registry)
    }

    fn load_feature(&self, id: &FeatureId) -> BackendResult<Feature> {
        let path = self.feature_path(id);
        let (mut feature, body) = read_md::<Feature>(&path)?;
        feature.body = body;
        Ok(feature)
    }

    fn save_feature(&mut self, feature: &Feature) -> BackendResult<()> {
        self.ensure_dirs().map_err(BackendError::Io)?;
        let path = self.feature_path(&feature.id);
        write_md(&path, feature, &feature.body)
    }

    fn load_story(&self, id: &StoryId) -> BackendResult<Story> {
        let path = self.story_path(id);
        let (mut story, body) = read_md::<Story>(&path)?;
        story.body = body;
        Ok(story)
    }

    fn save_story(&mut self, story: &Story) -> BackendResult<()> {
        self.ensure_dirs().map_err(BackendError::Io)?;
        let path = self.story_path(&story.id);
        write_md(&path, story, &story.body)
    }

    fn load_decision(&self, id: &DecisionId) -> BackendResult<Decision> {
        let path = self.decision_path(id);
        let (mut decision, body) = read_md::<Decision>(&path)?;
        decision.body = body;
        Ok(decision)
    }

    fn save_decision(&mut self, decision: &Decision) -> BackendResult<()> {
        self.ensure_dirs().map_err(BackendError::Io)?;
        let path = self.decision_path(&decision.id);
        write_md(&path, decision, &decision.body)
    }

    fn next_id(&self, kind: IdKind) -> String {
        match kind {
            IdKind::Feature => FeatureId::new(self.registry.next_feature_id).0,
            IdKind::Story => StoryId::new(self.registry.next_story_id).0,
            IdKind::Decision => DecisionId::new(self.registry.next_decision_id).0,
        }
    }

    fn search(&self, query: &str) -> Vec<SearchResult> {
        let q = query.to_lowercase();
        let mut results = Vec::new();

        for f in &self.registry.features {
            if f.title.to_lowercase().contains(&q) || f.body.to_lowercase().contains(&q) {
                results.push(SearchResult {
                    id: f.id.0.clone(),
                    kind: SearchKind::Feature,
                    title: f.title.clone(),
                    excerpt: f.body.chars().take(200).collect(),
                });
            }
        }

        for s in &self.registry.stories {
            if s.title.to_lowercase().contains(&q) || s.body.to_lowercase().contains(&q) {
                results.push(SearchResult {
                    id: s.id.0.clone(),
                    kind: SearchKind::Story,
                    title: s.title.clone(),
                    excerpt: s.body.chars().take(200).collect(),
                });
            }
        }

        for d in &self.registry.decisions {
            if d.title.to_lowercase().contains(&q) || d.body.to_lowercase().contains(&q) {
                results.push(SearchResult {
                    id: d.id.0.clone(),
                    kind: SearchKind::Decision,
                    title: d.title.clone(),
                    excerpt: d.body.chars().take(200).collect(),
                });
            }
        }

        results
    }
}

