use anyhow::{Context, Result};
use serde::de::DeserializeOwned;

pub struct ParsedMarkdown<T> {
    pub frontmatter: T,
    pub body: String,
}

pub fn parse_frontmatter<T: DeserializeOwned>(content: &str) -> Result<ParsedMarkdown<T>> {
    let content = content.trim_start();
    if !content.starts_with("---") {
        anyhow::bail!("missing frontmatter delimiter (---)");
    }

    let rest = &content[3..];
    let end = rest
        .find("\n---")
        .or_else(|| rest.find("---"))
        .context("missing closing frontmatter delimiter")?;

    let toml_str = &rest[..end];
    let body = rest[end + 3..].trim_start().to_string();

    let frontmatter = toml::from_str(toml_str)
        .with_context(|| format!("failed to parse frontmatter TOML:\n{toml_str}"))?;

    Ok(ParsedMarkdown { frontmatter, body })
}

pub fn render_frontmatter<T: serde::Serialize>(frontmatter: &T, body: &str) -> Result<String> {
    let toml_str = toml::to_string(frontmatter).context("failed to serialize frontmatter")?;
    Ok(format!("---\n{}---\n\n{}", toml_str.trim_end(), body))
}

#[cfg(test)]
mod tests {
    use super::*;
    use serde::{Deserialize, Serialize};

    #[derive(Debug, Serialize, Deserialize, PartialEq)]
    struct TestFm {
        id: String,
        title: String,
    }

    #[test]
    fn roundtrip_frontmatter() {
        let fm = TestFm {
            id: "FIR-1".into(),
            title: "Test feature".into(),
        };
        let rendered = render_frontmatter(&fm, "body content").unwrap();
        let parsed = parse_frontmatter::<TestFm>(&rendered).unwrap();
        assert_eq!(parsed.frontmatter, fm);
        assert_eq!(parsed.body, "body content");
    }

    #[test]
    fn parse_missing_delimiter_fails() {
        let result = parse_frontmatter::<TestFm>("no delimiter here");
        assert!(result.is_err());
    }

    #[test]
    fn parse_missing_closing_delimiter_fails() {
        let result = parse_frontmatter::<TestFm>("---\nid = \"x\"\ntitle = \"y\"\nno closing");
        assert!(result.is_err());
    }

    #[test]
    fn parse_invalid_toml_fails() {
        let result = parse_frontmatter::<TestFm>("---\nid = \n---\n\nbody");
        assert!(result.is_err());
    }

    #[test]
    fn body_preserved_through_roundtrip() {
        let fm = TestFm {
            id: "FIR-1".into(),
            title: "Test".into(),
        };
        let body = "# Heading\n\nSome markdown content\n- item 1\n- item 2\n";
        let rendered = render_frontmatter(&fm, body).unwrap();
        let parsed = parse_frontmatter::<TestFm>(&rendered).unwrap();
        assert_eq!(parsed.body, body);
    }
}

